  function contextLockCurrentChapters() {
    const chapters = new Set(currentStudyScopePages()
      .filter((page) => /^Matthew$/i.test(pageBookName(page)))
      .map((page) => pageChapterNumber(page))
      .filter(Boolean));
    const latestChapters = new Set();
    [
      pageRecordFromCapture(studyData.latestCapture),
      pageRecordFromStatus(studyData.analysisStatus || {}),
      rawPageRecordFromCapture(studyData.latestCapture),
      {
        sourceTitle: studyData.latestCapture?.title || studyData.analysisStatus?.sourceCaptureTitle || "",
        activeUrl: studyData.latestCapture?.url || studyData.analysisStatus?.activeUrl || "",
        sourceCaptureBook: studyData.analysisStatus?.sourceCaptureBook || "",
        sourceCaptureChapter: studyData.analysisStatus?.sourceCaptureChapter || ""
      }
    ].filter(Boolean).forEach((page) => {
      const fromTitle = sourceMatchFromTitle(page.sourceTitle || page.title || "");
      const fromUrl = sourceMatchFromUrl(page.activeUrl || page.url || "");
      const book = pageBookName(page) || fromTitle?.book || fromUrl?.book || "";
      const chapter = pageChapterNumber(page) || Number(fromTitle?.chapter || fromUrl?.chapter || 0);
      if (/^Matthew$/i.test(book) && chapter) latestChapters.add(chapter);
    });
    if (!analyzedPageHistory().length && latestChapters.size) return latestChapters;
    latestChapters.forEach((chapter) => chapters.add(chapter));
    return chapters;
  }

  function contextLockRecordSearchText(item = {}) {
    return [
      item.lockName,
      item.eventScope,
      item.speaker,
      item.audience,
      item.authoritySource,
      item.messenger,
      item.recipient,
      item.participants,
      item.location,
      item.groundedObservations,
      item.supportedMeaning,
      item.validationChecks,
      item.rejectedInversions,
      item.sourcePhrase,
      item.scopeBoundary,
      item.provenance
    ].flat(Infinity).map((value) => normalizeText(value)).join(" ");
  }

  const CONTEXT_LOCK_PLACE_PATTERN = /^(?:Nazareth|Egypt|Jerusalem|Galilee|wilderness|Jordan|Capernaum|Bethlehem|Judaea|JudÃ¦a|land of Israel|Israel|Babylon|mountain|sea|river|city|village)$/i;

  function isContextLockPlaceName(value = "") {
    const normalized = normalizeText(value).replace(/^(?:the\s+)?(?:city|town|land|parts|region)\s+(?:of\s+)?/i, "");
    if (!normalized) return false;
    if (CONTEXT_LOCK_PLACE_PATTERN.test(normalized)) return true;
    return /\b(?:city|town|village|land|region|wilderness|mountain|river|sea|coast|border|parts of)\b/i.test(value) &&
      /\b(?:Nazareth|Egypt|Jerusalem|Galilee|Jordan|Capernaum|Bethlehem|Judaea|JudÃ¦a|Israel|Babylon)\b/i.test(value);
  }

  function isContextLockSourceLabel(value = "") {
    return /^(?:Matthew|Mark|Luke|John)$/i.test(normalizeText(value));
  }

  function contextLockActorParticipants(values = []) {
    return uniqueStudyList(asArray(values))
      .filter((value) => value && !isContextLockPlaceName(value) && !isContextLockSourceLabel(value))
      .slice(0, 12);
  }

  function contextLockLocationText(location = "", values = []) {
    const places = uniqueStudyList(asArray(values).filter(isContextLockPlaceName));
    return uniqueStudyList([location, ...places].filter(Boolean)).join("; ");
  }

  function contextLockFallbackParticipants() {
    const participants = [];
    asArray(studyData.actorTimelines).map(dedupeActorActions).forEach((actor) => {
      participants.push(actor.resolvedActorName || actor.actorName);
    });
    scopedSemanticRecords(studyData.entityRegistry).forEach((item) => {
      const name = item.displayName || item.canonicalName || item.entityName;
      const kind = studyReferenceEntityKind(item);
      if (kind === "actor" || kind === "authority") participants.push(name);
    });
    return contextLockActorParticipants(participants)
      .filter((participant) => !studyReferenceIsTechnicalLabel(participant))
      .slice(0, 8);
  }

  function createContextLockRecord(candidate = {}) {
    const scope = currentStudyScopeLabel();
    const participantCandidates = asArray(candidate.participants);
    return {
      schemaVersion: 1,
      layer: "ICE_CONTEXT_LOCK",
      lockName: candidate.lockName || "Context Lock",
      speaker: candidate.speaker || "",
      audience: candidate.audience || "",
      authoritySource: candidate.authoritySource || "",
      messenger: candidate.messenger || "",
      recipient: candidate.recipient || "",
      participants: contextLockActorParticipants(participantCandidates),
      location: contextLockLocationText(candidate.location || "", participantCandidates),
      eventScope: candidate.eventScope || scope,
      sourcePhrase: candidate.sourcePhrase || "",
      verseRange: candidate.verseRange || "",
      scopePath: candidate.scopePath || "",
      sourceContext: candidate.sourceContext || {},
      groundedObservations: uniqueStudyList(asArray(candidate.groundedObservations)).slice(0, 10),
      supportedMeaning: uniqueStudyList(asArray(candidate.supportedMeaning)).slice(0, 10),
      validationChecks: uniqueStudyList(asArray(candidate.validationChecks)).slice(0, 10),
      rejectedInversions: uniqueStudyList(asArray(candidate.rejectedInversions)).slice(0, 10),
      scopeBoundary: candidate.scopeBoundary || `Context Lock applies only to confirmed records in ${scope}. Higher-level derived layers may depend on it but may not redefine it.`,
      evidenceWeight: candidate.evidenceWeight || "Context Lock / Direct Source Evidence",
      provenance: candidate.provenance || "I.C.E. Context Lock display diagnostics",
      confidence: candidate.confidence || "explicit",
      activeScope: scope
    };
  }

  function contextLockRecords() {
    const chapters = contextLockCurrentChapters();
    const records = [];
    const add = (candidate) => records.push(createContextLockRecord(candidate));
    const sourceContextForChapter = (chapter) => ({
      sourceTitle: `Matthew ${chapter}`,
      book: "Matthew",
      chapter: String(chapter),
      sourceUrl: `https://www.churchofjesuschrist.org/study/scriptures/nt/matt/${chapter}`
    });

    if (chapters.has(1)) {
      add({
        lockName: "Matthew 1 Angel/Joseph Revelation Context",
        speaker: "AngEL Of THE LORD",
        audience: "Joseph",
        authoritySource: "THE LORD / GOD",
        messenger: "AngEL Of THE LORD",
        recipient: "Joseph",
        participants: ["THE LORD / GOD", "AngEL Of THE LORD", "Joseph", "Mary", "JESUS"],
        location: "Dream context",
        eventScope: "Matthew 1:20-21",
        verseRange: "Matthew 1:20-21",
        scopePath: "scripture.nt.matthew.1.verse.20",
        sourceContext: sourceContextForChapter(1),
        sourcePhrase: "the angel of THE LORD appeared unto him in a dream, saying",
        groundedObservations: [
          "AngEL Of THE LORD appears to Joseph in a dream.",
          "AngEL Of THE LORD speaks/instructs Joseph.",
          "Joseph is the addressed recipient."
        ],
        supportedMeaning: [
          "Joseph receives revelation/instruction.",
          "AngEL Of THE LORD functions as messenger, not recipient.",
          "THE LORD / GOD remains the source authority where grounded by the revelation pattern."
        ],
        validationChecks: [
          "Source authority, messenger, and recipient are separate role slots.",
          "Higher layers may create message-delivery relationships but may not invert recipient roles.",
          "Timeline/Journey labels must preserve Joseph as recipient."
        ],
        rejectedInversions: [
          "Rejected: AngEL Of THE LORD receives revelation.",
          "Rejected: AngEL Of THE LORD replaces THE LORD / GOD as source authority.",
          "Rejected: Joseph becomes messenger for this verse context."
        ]
      });
    }

    if (chapters.has(2)) {
      add({
        lockName: "Matthew 2 Herod / Child Protection Context",
        speaker: "AngEL Of THE LORD / wise men / Herod by scene",
        audience: "Joseph, wise men, chief priests and scribes by scene",
        authoritySource: "THE LORD / GOD where angelic warning is grounded",
        messenger: "AngEL Of THE LORD for protective dream instructions",
        recipient: "Joseph for protective warning; wise men for warning of GOD",
        participants: ["Herod", "JESUS / young child", "Mary", "Joseph", "wise men", "AngEL Of THE LORD", "THE LORD / GOD"],
        location: "Judaea, Bethlehem, Egypt, land of Israel, Nazareth",
        eventScope: "Matthew 2",
        verseRange: "Matthew 2",
        scopePath: "scripture.nt.matthew.2",
        sourceContext: sourceContextForChapter(2),
        sourcePhrase: "Herod will seek the young child to destroy him; the angel of the Lord appeareth to Joseph",
        groundedObservations: [
          "Herod seeks the young child.",
          "Joseph receives protective instruction.",
          "The young child/JESUS is the protected target, not the hostile actor."
        ],
        supportedMeaning: [
          "Herod remains hostile authority in this scope.",
          "Joseph functions as obedient/protective steward.",
          "AngEL Of THE LORD functions as protective messenger where the dream instruction appears."
        ],
        validationChecks: [
          "Participant roles must not invert Herod and JESUS / young child.",
          "Protective movement records must not imply automatic page traversal.",
          "Fulfillment relationships remain study relationships, not context rewrites."
        ],
        rejectedInversions: [
          "Rejected: JESUS / young child as hostile seeker.",
          "Rejected: Herod as protected child.",
          "Rejected: AngEL Of THE LORD as source authority replacing THE LORD / GOD."
        ]
      });
    }

    if (chapters.has(5)) {
      add({
        lockName: "Matthew 5 Teacher / Audience Context",
        speaker: "JESUS",
        audience: "disciples with multitudes in scene context",
        authoritySource: "JESUS as teaching authority in source scene",
        messenger: "",
        recipient: "disciples / hearers",
        participants: ["JESUS", "disciples", "multitudes"],
        location: "Mountain teaching context",
        eventScope: "Matthew 5:1-2 and chapter teaching context",
        verseRange: "Matthew 5:1-2",
        scopePath: "scripture.nt.matthew.5.verse.1",
        sourceContext: sourceContextForChapter(5),
        sourcePhrase: "he went up into a mountain: and when he was set, his disciples came unto him: And he opened his mouth, and taught them",
        groundedObservations: [
          "JESUS sees the multitudes.",
          "JESUS goes up into a mountain.",
          "Disciples come unto Him.",
          "JESUS teaches."
        ],
        supportedMeaning: [
          "JESUS is the teacher/speaker for the discourse.",
          "Disciples are the immediate teaching audience in the source wording.",
          "Multitudes remain scene context unless a record explicitly narrows or expands the audience."
        ],
        validationChecks: [
          "Teaching, principle, and theme layers may depend on teacher/audience context but may not redefine it.",
          "Mercy, Kingdom of Heaven, and righteousness themes remain study relationships.",
          "Possible audience implications must not be promoted to explicit source facts."
        ],
        rejectedInversions: [
          "Rejected: disciples as source teacher for the Sermon.",
          "Rejected: themes/principles as the source speaker.",
          "Rejected: possible audience implications as explicit facts."
        ]
      });
    }

    if (!records.length) {
      const active = activeSourcePageRecord();
      if (active) {
        add({
          lockName: `${volumePageLabel(active)} Source Context Lock`,
          eventScope: volumePageLabel(active),
          participants: contextLockFallbackParticipants(),
          location: "",
          sourceContext: {
            sourceTitle: active.sourceTitle,
            sourceUrl: active.activeUrl,
            book: active.sourceCaptureBook,
            chapter: active.sourceCaptureChapter
          },
          groundedObservations: ["Current source page is locked as the lower-level context for derived Study Panel records."],
          supportedMeaning: ["Derived layers may summarize or relate current-scope records, but they may not redefine the source page context."],
          validationChecks: ["Reject role, authority, participant, or recipient changes not grounded by lower stages."],
          rejectedInversions: ["Rejected: unselected/global page context replacing the active Study Scope."]
        });
      }
    }

    return records.slice(0, 12);
  }

  function contextLockSearchText(item = {}) {
    return contextLockRecordSearchText(item);
  }

  function createContextLockCard(item = {}) {
    const card = document.createElement("article");
    card.className = "study-card semantic-card context-lock-card";
    const header = document.createElement("header");
    header.className = "semantic-card-header";
    const heading = document.createElement("h3");
    const divineContext = hasDivineDisplayContext([item.lockName, item.authoritySource, item.messenger, item.recipient, item.participants]);
    heading.textContent = renderDerivedSemanticDisplayText(item.lockName || "Context Lock", divineContext);
    const range = document.createElement("div");
    range.className = "semantic-card-range";
    range.textContent = ["ICE_CONTEXT_LOCK", item.eventScope || item.activeScope, displayConfidence(item.confidence || "explicit")].filter(Boolean).join(" | ");
    const body = document.createElement("div");
    body.className = "semantic-card-body";
    header.append(heading, range);
    [
      createPassageFunctionSection("Speaker", item.speaker || "Not recorded.", { divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Audience", item.audience || "Not recorded.", { divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Authority Source", item.authoritySource || "Not recorded.", { divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Messenger", item.messenger || "Not recorded.", { divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Recipient", item.recipient || "Not recorded.", { divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Participants", "", { list: item.participants, plainList: true, divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Location", item.location || "Not recorded.", { preserveExact: true }),
      createPassageFunctionSection("Event Scope", item.eventScope || item.activeScope || "Current Study Scope", { preserveExact: true }),
      renderSourceVerseRef(item),
      createPassageFunctionSection("Grounded Observations", "", { list: item.groundedObservations, plainList: true, divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Supported Meaning", "", { list: item.supportedMeaning, plainList: true, divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Validation Checks", "", { list: item.validationChecks, plainList: true, preserveExact: true }),
      createPassageFunctionSection("Rejected Inversions", "", { list: item.rejectedInversions, plainList: true, divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Scope Boundary", item.scopeBoundary, { preserveExact: true }),
      createPassageFunctionSection("Evidence Weight", item.evidenceWeight, { preserveExact: true }),
      createPassageFunctionSection("Provenance", item.provenance, { preserveExact: true }),
      createWordingProvenanceSection({ source: item.provenance, label: item.lockName, layer: "Context Lock / ICE_CONTEXT_LOCK", storageKey: "Not persisted in Phase 9.8a", scopePath: item.eventScope || item.activeScope, rule: "Context Lock is display-only. Higher semantic layers may depend on locked context but may not rewrite speaker, audience, authority, messenger, recipient, participant, location, or event-scope facts." })
    ].filter(Boolean).forEach((section) => body.appendChild(section));
    card.append(header, body);
    return card;
  }

  function renderContextLock(term) {
    const container = document.getElementById("contextLockCards");
    const count = document.getElementById("contextLockCount");
    if (!container || !count) return;
    const records = contextLockRecords();
    const filtered = records.filter((item) => matchesSearchQuery(contextLockSearchText(item), term));
    clearElement(container);
    count.textContent = `${filtered.length} lock record(s)`;
    if (!records.length) {
      appendEmpty(container, "No Context Lock diagnostics are available for the current Study Scope.");
      return;
    }
    container.appendChild(createCard(
      "Context Lock",
      [
        `Derived records: ${records.length}`,
        "Layer identifier: ICE_CONTEXT_LOCK",
        "Purpose: preserve lower-level source/context role facts before higher semantic layers derive meaning.",
        "Boundary: display-only diagnostics; no extraction, doctrine generation, crawling, automatic analysis, or source-record rewrites."
      ].join("\n"),
      "derived context lock layer"
    ));
    if (!filtered.length) {
      appendEmpty(container, "No Context Lock records match current filter.");
      return;
    }
    filtered.slice(0, DISPLAY_LIMIT).forEach((item) => container.appendChild(createContextLockCard(item)));
  }

  function meaningStagingLadder() {
    return [
      { level: 0, stage: "Source Text", description: "The verse/source wording itself." },
      { level: 1, stage: "Context", description: "Who, what, where, when, speaker, audience, authority, and participants." },
      { level: 2, stage: "Grounded Observation", description: "Things explicitly stated." },
      { level: 3, stage: "Supported Meaning", description: "Things directly supported by source context." },
      { level: 4, stage: "Strongly Implied Meaning", description: "Things required or highly supported by context." },
      { level: 5, stage: "Possible Meaning", description: "Things plausible but not established." },
      { level: 6, stage: "Study Relationship", description: "Connections to themes, journeys, timelines, fulfillment, knowledge graph, and principle networks." }
    ];
  }

  function createMeaningStageRecord(candidate = {}) {
    const ladder = meaningStagingLadder().find((item) => item.stage === candidate.stage || item.level === candidate.level) || meaningStagingLadder()[6];
    return {
      schemaVersion: 1,
      layer: "ICE_MEANING_STAGING",
      id: candidate.id || `meaning-stage-${ladder.level}-${normalizeText(candidate.recordLabel || candidate.stage).toLowerCase().replace(/[^a-z0-9]+/g, "-")}`,
      stageLevel: ladder.level,
      stage: ladder.stage,
      stageDescription: ladder.description,
      recordLabel: candidate.recordLabel || ladder.stage,
      reasoning: candidate.reasoning || "",
      derivedFromStages: uniqueStudyList(asArray(candidate.derivedFromStages)).slice(0, 8),
      validationChecks: uniqueStudyList(asArray(candidate.validationChecks)).slice(0, 8),
      challengeFactors: uniqueStudyList(asArray(candidate.challengeFactors)).slice(0, 8),
      sourcePhrase: candidate.sourcePhrase || "",
      verseRange: candidate.verseRange || "",
      scopePath: candidate.scopePath || "",
      sourceContext: candidate.sourceContext || {},
      relatedRecords: uniqueStudyList(asArray(candidate.relatedRecords)).slice(0, 8),
      evidenceWeight: candidate.evidenceWeight || "Meaning Staging / Display Diagnostic",
      provenance: candidate.provenance || "I.C.E. Meaning Staging display diagnostics",
      confidence: candidate.confidence || "probable",
      activeScope: currentStudyScopeLabel()
    };
  }

  function meaningStagingRecords() {
    const records = [];
    const locks = contextLockRecords();
    locks.forEach((lock) => {
      records.push(createMeaningStageRecord({
        level: 1,
        recordLabel: `${lock.lockName}: Context`,
        reasoning: "Context Lock records speaker, audience, authority, messenger, recipient, participants, location, and event scope before derived layers run.",
        derivedFromStages: ["Level 0 Source Text"],
        validationChecks: lock.validationChecks,
        challengeFactors: lock.rejectedInversions,
        sourcePhrase: lock.sourcePhrase,
        verseRange: lock.verseRange,
        scopePath: lock.scopePath,
        sourceContext: lock.sourceContext,
        relatedRecords: [lock.eventScope, ...lock.participants],
        evidenceWeight: lock.evidenceWeight,
        provenance: "I.C.E. Context Lock"
      }));
      lock.groundedObservations.forEach((observation, index) => records.push(createMeaningStageRecord({
        level: 2,
        recordLabel: observation,
        reasoning: "Grounded observation is explicitly tied to the locked source/context role facts.",
        derivedFromStages: ["Level 0 Source Text", "Level 1 Context"],
        validationChecks: ["Must not add participants or recipients not grounded by source/context."],
        challengeFactors: lock.rejectedInversions,
        sourcePhrase: lock.sourcePhrase,
        verseRange: lock.verseRange,
        scopePath: lock.scopePath,
        sourceContext: lock.sourceContext,
        relatedRecords: [lock.lockName],
        evidenceWeight: "Direct Source Evidence",
        provenance: `I.C.E. Meaning Staging from ${lock.lockName}`,
        id: `meaning-stage-observation-${lock.lockName}-${index}`
      })));
      lock.supportedMeaning.forEach((meaning, index) => records.push(createMeaningStageRecord({
        level: 3,
        recordLabel: meaning,
        reasoning: "Supported meaning follows directly from Source Text plus Context Lock without changing lower-level roles.",
        derivedFromStages: ["Level 0 Source Text", "Level 1 Context", "Level 2 Grounded Observation"],
        validationChecks: ["Lower-level speaker, authority, messenger, recipient, and participant roles remain unchanged."],
        challengeFactors: lock.rejectedInversions,
        sourcePhrase: lock.sourcePhrase,
        verseRange: lock.verseRange,
        scopePath: lock.scopePath,
        sourceContext: lock.sourceContext,
        relatedRecords: [lock.lockName],
        evidenceWeight: "Supported Meaning / Direct Context Support",
        provenance: `I.C.E. Meaning Staging from ${lock.lockName}`,
        id: `meaning-stage-supported-${lock.lockName}-${index}`
      })));
    });

    [
      ...journeyNodesRecords().slice(0, 8).map((item) => ({ label: `Journey Node: ${item.nodeName}`, item })),
      ...journeyPathRecords().slice(0, 8).map((item) => ({ label: `Journey Path: ${item.fromNode} -> ${item.toNode}`, item })),
      ...timelineEventsRecords().slice(0, 8).map((item) => ({ label: `Timeline Event: ${item.eventName}`, item })),
      ...studyThemeRecords().slice(0, 8).map((item) => ({ label: `Study Theme: ${item.themeName}`, item }))
    ].forEach(({ label, item }) => {
      records.push(createMeaningStageRecord({
        level: 6,
        recordLabel: label,
        reasoning: "Study relationship records connect already-grounded semantic records without redefining source text, context, observations, or supported meaning.",
        derivedFromStages: ["Level 1 Context", "Level 2 Grounded Observation", "Level 3 Supported Meaning"],
        validationChecks: [
          "Role inversion rejected.",
          "Authority inversion rejected.",
          "Participant inversion rejected.",
          "Unsupported recipient changes rejected."
        ],
        challengeFactors: ["Review source verse reference and evidence chain before treating a relationship as interpretive context."],
        sourcePhrase: item.sourcePhrase,
        verseRange: item.verseRange,
        scopePath: item.scopePath,
        sourceContext: item.sourceContext,
        relatedRecords: item.supportingRecords || item.relatedJourneyNodes || item.relatedTimelineEvents || item.relatedPrinciples,
        evidenceWeight: item.evidenceWeight,
        provenance: item.provenance || "I.C.E. derived study relationship",
        confidence: item.confidence
      }));
    });

    return records.slice(0, 48);
  }

  function meaningStagingSearchText(item = {}) {
    return [
      item.stage,
      item.recordLabel,
      item.reasoning,
      item.derivedFromStages,
      item.validationChecks,
      item.challengeFactors,
      item.sourcePhrase,
      item.relatedRecords,
      item.provenance,
      item.activeScope
    ].flat(Infinity).map((value) => normalizeText(value)).join(" ");
  }

  function createMeaningStagingCard(item = {}) {
    const card = document.createElement("article");
    card.className = "study-card semantic-card meaning-staging-card";
    const header = document.createElement("header");
    header.className = "semantic-card-header";
    const heading = document.createElement("h3");
    const divineContext = hasDivineDisplayContext([item.recordLabel, item.reasoning, item.relatedRecords]);
    heading.textContent = renderDerivedSemanticDisplayText(item.recordLabel || item.stage, divineContext);
    const range = document.createElement("div");
    range.className = "semantic-card-range";
    range.textContent = [`Level ${item.stageLevel}`, item.stage, item.activeScope].filter(Boolean).join(" | ");
    const body = document.createElement("div");
    body.className = "semantic-card-body";
    header.append(heading, range);
    [
      createPassageFunctionSection("Stage", item.stage || "Study Relationship", { preserveExact: true }),
      createPassageFunctionSection("Stage Meaning", item.stageDescription || "", { preserveExact: true }),
      createPassageFunctionSection("Reasoning", item.reasoning || "Not recorded.", { divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Derived From Stage(s)", "", { list: item.derivedFromStages, plainList: true, preserveExact: true }),
      createPassageFunctionSection("Validation Checks", "", { list: item.validationChecks, plainList: true, preserveExact: true }),
      createPassageFunctionSection("Challenge Factors", "", { list: item.challengeFactors, plainList: true, preserveExact: true }),
      renderSourceVerseRef(item),
      createPassageFunctionSection("Related Records", "", { list: item.relatedRecords, plainList: true, divineContext, preferHolySpirit: true }),
      createPassageFunctionSection("Evidence Weight", item.evidenceWeight || "Meaning Staging / Display Diagnostic", { preserveExact: true }),
      createPassageFunctionSection("Provenance", item.provenance || "I.C.E. Meaning Staging", { preserveExact: true }),
      createWordingProvenanceSection({ source: item.provenance || "I.C.E. Meaning Staging", label: item.recordLabel || item.stage, layer: "Meaning Staging / ICE_MEANING_STAGING", storageKey: "Not persisted in Phase 9.8a", scopePath: item.activeScope, rule: "Meaning Staging is display-only. Higher stages may depend on lower stages, but lower stages may never be modified by higher-level derived meanings or study relationships." })
    ].filter(Boolean).forEach((section) => body.appendChild(section));
    card.append(header, body);
    return card;
  }

  function renderMeaningStaging(term) {
    const container = document.getElementById("meaningStagingCards");
    const count = document.getElementById("meaningStagingCount");
    if (!container || !count) return;
    const records = meaningStagingRecords();
    const filtered = records.filter((item) => matchesSearchQuery(meaningStagingSearchText(item), term));
    clearElement(container);
    count.textContent = `${filtered.length} staging record(s)`;
    if (!records.length) {
      appendEmpty(container, "No Meaning Staging diagnostics are available for the current Study Scope.");
      return;
    }
    container.appendChild(createCard(
      "Meaning Staging",
      [
        `Derived records: ${records.length}`,
        "Layer identifier: ICE_MEANING_STAGING",
        "Purpose: show the inference ladder from Source Text through Context, Observation, Meaning, and Study Relationships.",
        "Boundary: display-only diagnostics; no new semantic extraction, doctrine generation, crawling, automatic analysis, or lower-stage rewrites."
      ].join("\n"),
      "derived meaning staging layer"
    ));
    if (!filtered.length) {
      appendEmpty(container, "No Meaning Staging records match current filter.");
      return;
    }
    filtered.slice(0, DISPLAY_LIMIT).forEach((item) => container.appendChild(createMeaningStagingCard(item)));
    if (filtered.length > DISPLAY_LIMIT) appendEmpty(container, `${filtered.length - DISPLAY_LIMIT} more staging record(s) hidden by the preview limit. Use panel search to focus a stage.`);
  }

  function studyReferenceNormalizeLabel(value = "") {
    return normalizeText(value).replace(/\s+/g, " ").trim();
  }

  function studyReferenceRoleLabel(value = "") {
    const text = normalizeText(value).toLowerCase();
    if (/authority|source authority|divine source/.test(text)) return "authority";
    if (/messenger|angel/.test(text)) return "messenger";
    if (/recipient|listener|audience|hearer/.test(text)) return "recipient";
    if (/speaker|teacher/.test(text)) return "speaker";
    if (/narrator|source/.test(text)) return "narrator";
    if (/participant|actor|person|group|ruler|ancestor/.test(text)) return "participant";
    return studyReferenceNormalizeLabel(value) || "participant";
  }

  function studyReferenceIsTechnicalLabel(value = "") {
    const label = studyReferenceNormalizeLabel(value).toLowerCase();
    return !label
      || /^(unknown actor|unknown|unresolved|current analyzed source|current source text|source reference unavailable|current source|current scope|not recorded)$/i.test(label)
      || /^source\b/.test(label);
  }

  function studyReferenceIsSourceNarratorOnly(item = {}) {
    const label = studyReferenceNormalizeLabel(item.label).toLowerCase();
    const roles = Array.from(item.roles || []).map((role) => normalizeText(role).toLowerCase());
    return ["scripture narrator", "matthew"].includes(label) && roles.every((role) => /narrator|source/.test(role));
  }

  function studyReferenceIsDivineAuthorityLabel(value = "") {
    const label = normalizedEntityName(value);
    return ["the lord", "god", "jesus christ", "jesus"].includes(label);
  }

  function currentScopeEvidenceText() {
    return normalizeText([
      currentStudyScopeLabel(),
      studyData.latestCapture,
      studyData.analysisStatus,
      studyData.activeSourcePage,
      studyData.canonicalAnalysisTarget
    ].map((value) => {
      if (value == null) return "";
      if (typeof value === "string") return value;
      try {
        return JSON.stringify(value);
      } catch (_error) {
        return String(value);
      }
    }).join(" "));
  }

  function locationGroundedInCurrentScope(name = "", record = {}) {
    const label = studyReferenceNormalizeLabel(name);
    if (studyReferenceIsTechnicalLabel(label)) return false;
    const recordEvidence = normalizeText([
      record.sourcePhrase,
      record.sourceSnippet,
      record.evidence,
      record.sourceGrounding,
      record.verseRange,
      record.scopePath,
      record.sourceContext?.sourceTitle,
      record.sourceContext?.sourceUrl
    ].flat(Infinity).join(" "));
    if (recordEvidence && new RegExp(`\\b${escapeRegExp(label)}\\b`, "i").test(recordEvidence)) return true;
    return new RegExp(`\\b${escapeRegExp(label)}\\b`, "i").test(currentScopeEvidenceText());
  }

  function relationshipGraphRecordAllowedInCurrentScope(record = {}) {
    if (!recordMatchesCurrentStudyScope(record)) return false;
    const relationshipText = normalizeText([
      record.relationshipType,
      record.semanticCategory,
      record.eventType,
      record.passageFunction
    ].join(" ")).toLowerCase();
    if (!/messianic_location_fulfillment|location_fulfillment/.test(relationshipText)) return true;
    const evidenceText = normalizeText([
      record.sourcePhrase,
      record.evidencePhrase,
      record.sourceGrounding,
      record.verseRange,
      record.scopePath,
      record.sourceContext?.sourceTitle,
      record.sourceContext?.sourceUrl
    ].flat(Infinity).join(" "));
    return /\b(?:egypt|nazareth|nazarene)\b/i.test(evidenceText);
  }

  function studyReferenceEntityKind(record = {}) {
    const text = normalizeText([
      record.entityType,
      record.type,
      record.category,
      record.actorCategory,
      record.roleType,
      record.roleHint,
      record.canonicalRole,
      record.semanticRole,
      record.entityClass,
      record.entityName,
      record.canonicalName,
      record.displayName
    ].join(" ")).toLowerCase();
    const name = normalizeText(record.displayName || record.canonicalName || record.entityName || record.mentionText || record.actorName);
    if (isContextLockPlaceName(name) || /\b(location|place|city|region|nation|wilderness|mountain|river|sea|body of water|geographic)\b/.test(text)) return "location";
    if (/\b(authority|divine entity|god|the lord)\b/.test(text)) return "authority";
    if (/\b(narrator|source label)\b/.test(text)) return "narrator";
    if (/\b(messenger)\b/.test(text)) return "actor";
    if (/\b(actor|person|group|ruler|ancestor|recipient|speaker|audience|participant)\b/.test(text)) return "actor";
    return "entity";
  }

  function studyReferenceStripDisplayQualifier(value = "") {
    return studyReferenceNormalizeLabel(value)
      .replace(/\s+by scene$/i, "")
      .replace(/\s+where\b.*$/i, "")
      .replace(/\s+for\b.*$/i, "")
      .trim();
  }

  function studyReferenceCanonicalDisplayLabel(value = "") {
    const label = studyReferenceStripDisplayQualifier(value);
    if (!label) return "";
    if (/^the lord\s*\/\s*god$/i.test(label)) return "THE LORD / GOD";
    if (/^jesus\s*\/\s*young child$/i.test(label)) return "JESUS / young CHILD";
    if (/^angel of the lord$/i.test(label) || /^angel of the lord$/i.test(label.replace(/AngEL/i, "Angel"))) return "AngEL Of THE LORD";
    if (/^wise men$/i.test(label)) return "wise men";
    if (/^herod$/i.test(label)) return "Herod";
    if (/^joseph$/i.test(label)) return "Joseph";
    if (/^mary$/i.test(label)) return "Mary";
    return label;
  }

  function studyReferenceCanonicalDisplayEntries(name = "", detail = {}) {
    const label = studyReferenceNormalizeLabel(name);
    if (!label) return [];
    if (detail.includeTechnical) return [{ label, roles: detail.roles }];
    const sourceRoles = asArray(detail.roles);
    const pieces = label.split(/\s*;\s*/).flatMap((piece) => {
      const clean = studyReferenceStripDisplayQualifier(piece);
      if (/^the lord\s*\/\s*god\b/i.test(clean)) return ["THE LORD / GOD"];
      if (/^jesus\s*\/\s*young child\b/i.test(clean)) return ["JESUS / young CHILD"];
      if (/\s+\/\s+/.test(clean)) return clean.split(/\s+\/\s+/);
      return [clean];
    });
    const bySceneSpeaker = /\bby scene\b/i.test(label) && sourceRoles.some((role) => /speaker/i.test(role));
    return pieces
      .map((piece, index) => {
        const canonical = studyReferenceCanonicalDisplayLabel(piece);
        if (!canonical) return null;
        const roles = bySceneSpeaker && index > 0 ? ["participant"] : sourceRoles;
        return { label: canonical, roles };
      })
      .filter(Boolean);
  }

  function addStudyReferenceItem(map, name, detail = {}) {
    const entries = studyReferenceCanonicalDisplayEntries(name, detail);
    if (!entries.length) return;
    entries.forEach((entry) => {
    const label = studyReferenceNormalizeLabel(entry.label);
    if (!label) return;
    if (!detail.includeTechnical && studyReferenceIsTechnicalLabel(label)) return;
    const key = label.toLowerCase();
    const existing = map.get(key) || {
      label,
      roles: new Set(),
      sources: new Set()
    };
    if (studyReferenceIsDivineAuthorityLabel(label)) existing.roles.add("authority");
    asArray(entry.roles).forEach((role) => {
      const normalized = studyReferenceRoleLabel(role);
      if (normalized) existing.roles.add(normalized);
    });
    if (existing.roles.has("authority")) existing.roles.delete("participant");
    asArray(detail.sources).forEach((source) => {
      const normalized = studyReferenceNormalizeLabel(source);
      if (normalized) existing.sources.add(normalized);
    });
    map.set(key, existing);
    });
  }

  function studyReferenceListFromItems(items = [], limit = 14, options = {}) {
    return asArray(items)
      .filter((item) => options.includeTechnical || (!studyReferenceIsTechnicalLabel(item.label) && !studyReferenceIsSourceNarratorOnly(item)))
      .sort((left, right) => left.label.localeCompare(right.label))
      .slice(0, limit)
      .map((item) => {
        const roles = Array.from(item.roles).slice(0, 4);
        const sources = Array.from(item.sources).slice(0, 2);
        return `${item.label}${roles.length ? ` - ${roles.join(", ")}` : ""}${sources.length ? ` (${sources.join("; ")})` : ""}`;
      });
  }

  function studyReferenceListFromMap(map, limit = 14, options = {}) {
    return studyReferenceListFromItems(Array.from(map.values()), limit, options);
  }

  function studyReferenceIsTechnicalActorItem(item = {}) {
    const label = studyReferenceNormalizeLabel(item.label).toLowerCase();
    const roles = Array.from(item.roles || []).map((role) => normalizeText(role).toLowerCase());
    if (studyReferenceIsTechnicalLabel(label)) return true;
    if (["scripture narrator", "quoted prophet", "matthew"].includes(label)) return true;
    return roles.some((role) => /narrator|unresolved|source/.test(role));
  }

  function studyReferenceActors(options = {}) {
    const actors = new Map();
    asArray(studyData.actorTimelines).map(dedupeActorActions).forEach((actor) => {
      addStudyReferenceItem(actors, actor.resolvedActorName || actor.actorName, {
        roles: [actor.actorFunction, actor.actorCategory, actor.resolutionSource],
        sources: ["Actor Timelines"],
        includeTechnical: options.includeTechnical
      });
    });
    contextLockRecords().forEach((lock) => {
      addStudyReferenceItem(actors, lock.authoritySource, { roles: ["authority"], sources: [lock.lockName], includeTechnical: options.includeTechnical });
      addStudyReferenceItem(actors, lock.messenger, { roles: ["messenger"], sources: [lock.lockName], includeTechnical: options.includeTechnical });
      addStudyReferenceItem(actors, lock.recipient, { roles: ["recipient"], sources: [lock.lockName], includeTechnical: options.includeTechnical });
      addStudyReferenceItem(actors, lock.speaker, { roles: ["speaker"], sources: [lock.lockName], includeTechnical: options.includeTechnical });
      asArray(lock.participants).forEach((participant) => addStudyReferenceItem(actors, participant, { roles: ["participant"], sources: [lock.lockName], includeTechnical: options.includeTechnical }));
    });
    return actors;
  }

  function studyReferenceEntitiesAndLocations(options = {}) {
    const entities = new Map();
    const locations = new Map();
    const addEntity = (record = {}, source = "Entity Registry") => {
      const name = record.displayName || record.canonicalName || record.entityName || record.mentionText || record.semanticItem || record.label;
      if (!name) return;
      if (!options.includeTechnical && studyReferenceIsTechnicalLabel(name)) return;
      const kind = studyReferenceEntityKind(record);
      if (kind === "location" && !locationGroundedInCurrentScope(name, record)) return;
      const target = kind === "location" ? locations : entities;
      addStudyReferenceItem(target, name, {
        roles: [kind === "location" ? "location / place" : (record.entityType || record.type || record.category || record.roleHint || kind)],
        sources: [source],
        includeTechnical: options.includeTechnical
      });
    };
    scopedSemanticRecords(studyData.entityRegistry).forEach((record) => addEntity(record, "Entity Registry"));
    scopedSemanticRecords(studyData.canonicalIdentities).forEach((record) => addEntity(record, "Canonical Identities"));
    scopedSemanticRecords(studyData.mentionIndex).forEach((record) => addEntity(record, "Mention Index"));
    contextLockRecords().forEach((lock) => {
      asArray(String(lock.location || "").split(/;|,/)).forEach((place) => {
        if (!locationGroundedInCurrentScope(place, lock)) return;
        addStudyReferenceItem(locations, place, { roles: ["where / place reference"], sources: [lock.lockName], includeTechnical: options.includeTechnical });
      });
    });
    return { entities, locations };
  }

  function studyReferenceNarrativeType(record = {}) {
    const text = normalizeText([
      record.eventType,
      record.eventDisplayLabel,
      record.eventClassification,
      record.eventText,
      record.sourcePhrase,
      record.sceneType,
      record.passageFunction,
      record.teachingTopic,
      record.relationshipType
    ].join(" ")).toLowerCase();
    if (/lineage|genealogy|generation|begat/.test(text)) return "Lineage Record";
    if (/narrator|testimony|witness/.test(text)) return "Narrator Testimony";
    if (/teach|discourse|sermon|beatitude|commandment|doctrine|these sayings|sayings of mine|heareth these sayings|whosoever heareth|doeth them|likened unto|wise man|foolish man/.test(text)) return "Teaching / Discourse";
    if (/heal|cleans|sick|leper|palsy|fever/.test(text)) return "Healing Account";
    if (/came|went|depart|entered|ship|sea|mountain|wilderness|travel|movement/.test(text)) return "Movement Account";
    if (/follow|call|disciple/.test(text)) return "Calling Account";
    if (/fulfill|prophet|spoken/.test(text)) return "Fulfillment Statement";
    if (/angel|dream|reveal|warn|messenger/.test(text)) return "Revelation / Messenger Event";
    if (/miracle|marvel|devil|spirit|cast out|rebuke|storm|wind/.test(text)) return "Miracle Account";
    if (/location|place|city|region|land/.test(text)) return "Location Account";
    if (/dialogue|request|answer|said|saying|asked/.test(text)) return "Dialogue / Request Event";
    return "Grounded Source Record";
  }

  function studyReferenceUserFacingEventType(record = {}) {
    const inferred = studyReferenceNarrativeType(record);
    const provided = normalizeText(record.eventType || record.eventDisplayLabel || record.eventClassification);
    if (/travel|movement/i.test(provided) && /Teaching|Discourse|Instruction/i.test(inferred)) return inferred;
    return provided || inferred;
  }

  function studyReferenceEvents() {
    const events = [];
    timelineSequenceRecords().slice(0, 20).forEach((item) => events.push({
      label: `${item.sequenceNumber}. ${item.event}`,
      type: studyReferenceUserFacingEventType(item),
      source: item.verseRange || item.scopePath || item.activeScope,
      grounding: item.sourcePhrase || item.sourceGrounding || item.derivedMeaning
    }));
    if (!events.length) {
      asArray(studyData.orderedEvents).slice(0, 20).forEach((item) => events.push({
        label: orderedEventTitle(item),
        type: orderedEventDisplayType(item),
        source: item.sourceTitle || item.scopePath || "Ordered Events",
        grounding: item.eventText
      }));
    }
    return events;
  }

  function studyReferenceNarrativeTypes(events = studyReferenceEvents()) {
    const counts = new Map();
    events.forEach((event) => counts.set(event.type || "Grounded Source Record", (counts.get(event.type || "Grounded Source Record") || 0) + 1));
    if (!counts.size) {
      scopedSemanticRecords(studyData.passageFunctions).forEach((item) => {
        const type = studyReferenceNarrativeType(item);
        counts.set(type, (counts.get(type) || 0) + 1);
      });
    }
    return Array.from(counts.entries())
      .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0]))
      .map(([type, value]) => `${type}: ${value}`);
  }

  function studyReferenceInferenceRecords() {
    const staging = meaningStagingRecords();
    if (staging.length) {
      return staging.slice(0, 18).map((item) => `Level ${item.stageLevel} - ${item.stage}: ${trimText(item.recordLabel, 120)}`);
    }
    return [
      "Level 0 - Source Text: source wording remains the starting point.",
      "Level 1 - Context: speaker, audience, authority, participants, and locations are locked before meaning.",
      "Level 2 - Grounded Observation: explicitly stated facts remain separate from interpretation.",
      "Level 3 - Supported Meaning: directly supported conclusions may be shown with provenance.",
      "Level 4 - Strongly Implied Meaning: highly supported implications must remain labeled.",
      "Level 5 - Possible Meaning: plausible context must not be shown as fact.",
      "Level 6 - Study Relationship: themes, journeys, timelines, and relationships cannot rewrite lower levels."
    ];
  }

  function studyReferenceIndexRecords() {
    const actors = studyReferenceActors();
    const { entities, locations } = studyReferenceEntitiesAndLocations();
    const events = studyReferenceEvents();
    return [{
      id: "study-reference-index-current",
      activeScope: currentStudyScopeLabel(),
      actors: studyReferenceListFromMap(actors),
      entities: studyReferenceListFromMap(entities),
      locations: studyReferenceListFromMap(locations),
      events,
      narrativeTypes: studyReferenceNarrativeTypes(events),
      inferenceLevels: studyReferenceInferenceRecords(),
      scopeBoundary: `Current Study Scope only: ${currentStudyScopeLabel()}. Retained records do not redefine this index.`,
      provenance: "I.C.E. Study Reference Index derived from current scoped Context Lock, Actor Timelines, Entity Registry, Timeline Events, Timeline Sequence, Ordered Events, Passage Functions, and Meaning Staging.",
      evidenceWeight: "Derived Reference Index / Current Scope Summary",
      confidence: "probable"
    }];
  }

  function studyReferenceIndexSearchText(item = {}) {
    return [
      item.activeScope,
      item.actors,
      item.entities,
      item.locations,
      item.events.map((event) => [event.label, event.type, event.source, event.grounding].join(" ")),
      item.narrativeTypes,
      item.inferenceLevels,
      item.scopeBoundary,
      item.provenance
    ].flat(Infinity).map((value) => normalizeText(value)).join(" ");
  }

  function createStudyReferenceIndexCard(item = {}) {
    const card = document.createElement("article");
    card.className = "study-card semantic-card study-reference-index-card";
    const header = document.createElement("header");
    header.className = "semantic-card-header";
    const heading = document.createElement("h3");
    const range = document.createElement("div");
    const body = document.createElement("div");
    heading.textContent = "Current Scope Reference Index";
    range.className = "semantic-card-range";
    range.textContent = ["ICE_STUDY_REFERENCE_INDEX", item.activeScope, displayConfidence(item.confidence || "probable")].filter(Boolean).join(" | ");
    body.className = "semantic-card-body";
    header.append(heading, range);
    const eventLines = asArray(item.events).slice(0, 12).map((event) => [
      `${event.label} - ${event.type}`,
      event.source ? `Source: ${event.source}` : "",
      event.grounding ? `Grounding: ${trimText(event.grounding, 100)}` : ""
    ].filter(Boolean).join(" | "));
    [
      createPassageFunctionSection("Characters / Actors", item.actors.length ? "" : "No grounded actors found for the current Study Scope.", { list: item.actors, plainList: true, divineContext: true, preferHolySpirit: true }),
      createPassageFunctionSection("Entities", item.entities.length ? "" : "No non-actor entities found for the current Study Scope.", { list: item.entities, plainList: true, divineContext: true, preferHolySpirit: true }),
      createPassageFunctionSection("Locations", item.locations.length ? "" : "No grounded locations found for the current Study Scope.", { list: item.locations, plainList: true, preserveExact: true }),
      createPassageFunctionSection("Events", eventLines.length ? "" : "No ordered events found for the current Study Scope.", { list: eventLines, plainList: true, divineContext: true, preferHolySpirit: true }),
      createPassageFunctionSection("Narrative Type Classification", item.narrativeTypes.length ? "" : "No narrative type classification available for the current Study Scope.", { list: item.narrativeTypes, plainList: true, preserveExact: true }),
      createPassageFunctionSection("Inference Ladder", "", { list: item.inferenceLevels, plainList: true, preserveExact: true }),
      createPassageFunctionSection("Scope Boundary", item.scopeBoundary, { preserveExact: true }),
      createEvidenceWeightSection({ evidenceType: item.evidenceWeight, evidenceStrength: "reference index assembled from existing current-scope records only", sourceGrounding: item.scopeBoundary, supportingRecords: ["Context Lock", "Actor Timelines", "Entity Registry", "Timeline Sequence", "Meaning Staging"] }),
      createPassageFunctionSection("Provenance", item.provenance, { preserveExact: true, collapsed: true, summaryLabel: "Show Provenance" }),
      createPassageFunctionSection("Boundary Rules", "", {
        list: [
          "Context always wins.",
          "Meaning never rewrites context.",
          "Relationships never rewrite meaning.",
          "Possible meaning is labeled and never shown as fact.",
          "Actors, entities, locations, and narrative types remain distinct.",
          "No crawling, queue processing, automatic study progression, or scope mutation is performed."
        ],
        plainList: true,
        preserveExact: true,
        collapsed: true,
        summaryLabel: "Show boundary rules"
      }),
      createWordingProvenanceSection({ source: item.provenance, label: "Study Reference Index", layer: "Study Reference Index / ICE_STUDY_REFERENCE_INDEX", storageKey: "Not persisted in this phase", scopePath: item.activeScope, rule: "Study Reference Index is a display-only reference surface over existing current-scope records. It does not create a new inference engine, crawl, analyze, queue, navigate, or modify Study Scope." })
    ].filter(Boolean).forEach((section) => body.appendChild(section));
    card.append(header, body);
    return card;
  }

  function renderStudyReferenceIndex(term) {
    const container = document.getElementById("studyReferenceIndexCards");
    const count = document.getElementById("studyReferenceIndexCount");
    if (!container || !count) return;
    const records = studyReferenceIndexRecords();
    const filtered = records.filter((item) => matchesSearchQuery(studyReferenceIndexSearchText(item), term));
    clearElement(container);
    count.textContent = `${filtered.length} reference item(s)`;
    if (!filtered.length) {
      appendEmpty(container, "No Study Reference Index records match current filter.");
      return;
    }
    container.appendChild(createCard(
      "Study Reference Index",
      [
        `Derived records: ${records.length}`,
        "Layer identifier: ICE_STUDY_REFERENCE_INDEX",
        "Purpose: quick current-scope reference for actors, entities, locations, events, narrative types, ordered flow, and inference levels.",
        "Boundary: display-only index; no crawling, queue processing, automatic study progression, scope mutation, or new inference engine."
      ].join("\n"),
      "derived reference index layer"
    ));
    filtered.forEach((item) => container.appendChild(createStudyReferenceIndexCard(item)));
  }

  function crossReferenceRelationshipDirection(value = "") {
    const text = normalizeText(value).toLowerCase();
    if (/prior|before|earlier|setup|background|lineage|prophecy/.test(text)) return "prior";
    if (/future|later|fulfill|continue|expand|repeat|clarif|development/.test(text)) return "future";
    if (/related|echo|pattern|similar|theme|parallel|mirror/.test(text)) return "related";
    return "current";
  }

  function crossReferenceRelationshipType(value = "") {
    const text = normalizeText(value).toLowerCase();
    if (/authority/.test(text)) return "authority relationship";
    if (/speaker|audience|teach/.test(text)) return "speaker/audience relationship";
    if (/movement|travel|came|went|depart|location/.test(text)) return "movement relationship";
    if (/fulfill|prophecy/.test(text)) return "fulfillment relationship";
    if (/theme|principle|doctrine/.test(text)) return "theme relationship";
    if (/journey|path/.test(text)) return "journey relationship";
    if (/reference|cross-reference|source/.test(text)) return "reference relationship";
    return normalizeText(value) || "relationship";
  }

  function normalizeCrossReferenceRelationshipRecord(record = {}, fallback = {}) {
    const sourceScope = normalizeText(record.sourceScope || record.sourceReference || record.scopePath || record.verseRange || record.activeScope || fallback.sourceScope || currentStudyScopeLabel());
    const targetScope = normalizeText(record.targetScope || record.targetReference || record.toScope || record.toHref || record.toText || fallback.targetScope || "");
    const sourceEntity = normalizeText(record.sourceEntity || record.fromEntity || record.sourceCharacter || record.fromNode || record.sourcePhrase || fallback.sourceEntity || "");
    const targetEntity = normalizeText(record.targetEntity || record.toEntity || record.targetCharacter || record.toNode || record.targetPhrase || fallback.targetEntity || "");
    const relationshipType = crossReferenceRelationshipType(record.relationshipType || record.type || fallback.relationshipType || "");
    const relationshipDirection = crossReferenceRelationshipDirection(record.relationshipDirection || record.direction || fallback.relationshipDirection || relationshipType);
    const id = normalizeText(record.id || record.recordId || fallback.id || `${relationshipDirection}:${relationshipType}:${sourceScope}:${targetScope}:${sourceEntity}:${targetEntity}`).slice(0, 220);
    return {
      schemaVersion: 1,
      id,
      sourceScope,
      targetScope,
      relationshipType,
      relationshipDirection,
      sourceEntityOrEventOrTheme: sourceEntity || "current scope",
      targetEntityOrEventOrTheme: targetEntity || targetScope || "related record",
      evidenceStrength: normalizeText(record.evidenceStrength || record.evidenceWeight || record.confidence || fallback.evidenceStrength || "existing scoped record"),
      inferenceLevel: normalizeText(record.inferenceLevel || record.stage || fallback.inferenceLevel || "Study Relationship"),
      provenance: normalizeText(record.provenance || record.semanticSourceLayer || fallback.provenance || "I.C.E. Cross-Reference Relationship Summary"),
      confidence: normalizeText(record.confidence || record.appAccuracy || fallback.confidence || "supported")
    };
  }

  function storedCrossReferenceRelationshipRecords() {
    return asArray(studyData.crossReferenceRelationships)
      .map((record) => normalizeCrossReferenceRelationshipRecord(record))
      .filter((record) => recordMatchesCurrentStudyScope(record) || !record.sourceScope || record.sourceScope === currentStudyScopeLabel());
  }

  function derivedCurrentCrossReferenceRelationships() {
    const records = [];
    scopedSemanticRecords(studyData.relationshipGraph).filter((edge) => relationshipGraphRecordAllowedInCurrentScope(edge)).slice(0, 12).forEach((edge, index) => {
      records.push(normalizeCrossReferenceRelationshipRecord(edge, {
        id: `current-relationship-graph-${index}`,
        relationshipDirection: "current",
        relationshipType: edge.relationshipType || "relationship graph edge",
        sourceEntity: edge.fromEntity,
        targetEntity: edge.toEntity,
        provenance: "ICE_RELATIONSHIP_GRAPH current-scope edge"
      }));
    });
    scopedSemanticRecords(studyData.characterInteractions).slice(0, 8).forEach((item, index) => {
      records.push(normalizeCrossReferenceRelationshipRecord(item, {
        id: `current-character-interaction-${index}`,
        relationshipDirection: "current",
        relationshipType: item.interactionType || "actor relationship",
        sourceEntity: item.sourceCharacter,
        targetEntity: item.targetCharacter,
        provenance: "ICE_CHARACTER_INTERACTIONS current-scope relationship"
      }));
    });
    return records;
  }

  function derivedRelatedCrossReferenceRelationships() {
    const records = [];
    scopedSemanticRecords(studyData.referenceRoles).slice(0, 10).forEach((item, index) => {
      records.push(normalizeCrossReferenceRelationshipRecord(item, {
        id: `related-reference-role-${index}`,
        relationshipDirection: "related",
        relationshipType: item.role || item.referenceRole || "reference relationship",
        sourceEntity: item.sourceText || item.label,
        targetEntity: item.resolvedRole || item.toText,
        targetScope: item.toHref || item.reference || "",
        provenance: "ICE_REFERENCE_ROLES related reference candidate",
        inferenceLevel: "Study Relationship"
      }));
    });
    scopedSemanticRecords(studyData.referenceGraph).slice(0, 10).forEach((edge, index) => {
      records.push(normalizeCrossReferenceRelationshipRecord(edge, {
        id: `related-reference-graph-${index}`,
        relationshipDirection: "related",
        relationshipType: edge.relationshipType || "reference relationship",
        sourceEntity: edge.fromText || edge.sourceText,
        targetEntity: edge.toText || edge.targetText,
        targetScope: edge.toHref || edge.targetHref || "",
        provenance: "ICE_REFERENCE_GRAPH related reference candidate",
        inferenceLevel: "Study Relationship"
      }));
    });
    return records;
  }

  function crossReferenceRelationshipRecords() {
    const records = [
      ...storedCrossReferenceRelationshipRecords(),
      ...derivedCurrentCrossReferenceRelationships(),
      ...derivedRelatedCrossReferenceRelationships()
    ];
    const seen = new Set();
    return records.filter((record) => {
      const key = normalizeText(record.id).toLowerCase();
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }

  function crossReferenceRelationshipSummaryRecord() {
    const records = crossReferenceRelationshipRecords();
    const counts = records.reduce((memo, record) => {
      const direction = crossReferenceRelationshipDirection(record.relationshipDirection);
      memo[direction] = (memo[direction] || 0) + 1;
      return memo;
    }, { prior: 0, current: 0, future: 0, related: 0 });
    return {
      id: "cross-reference-relationship-summary-current",
      activeScope: currentStudyScopeLabel(),
      storageKey: STORAGE_KEYS.crossReferenceRelationships,
      relationshipRecordShape: [
        "sourceScope",
        "targetScope",
        "relationshipType",
        "relationshipDirection",
        "sourceEntityOrEventOrTheme",
        "targetEntityOrEventOrTheme",
        "evidenceStrength",
        "inferenceLevel",
        "provenance",
        "confidence"
      ],
      counts,
      records,
      trustRules: [
        "Prior may inform Current but may not rewrite Current context.",
        "Future may illuminate Current but may not redefine earlier source meaning.",
        "Related may connect but may not redefine source meaning.",
        "Context Lock remains authoritative.",
        "This summary does not crawl, navigate, process queues, or mutate scope."
      ]
    };
  }

  function crossReferenceRelationshipSummarySearchText(item = {}) {
    return [
      item.activeScope,
      item.storageKey,
      Object.entries(item.counts || {}).map(([key, value]) => `${key} ${value}`),
      item.records.map((record) => [record.relationshipDirection, record.relationshipType, record.sourceScope, record.targetScope, record.sourceEntityOrEventOrTheme, record.targetEntityOrEventOrTheme, record.provenance].join(" ")),
      item.trustRules
    ].flat(Infinity).map((value) => normalizeText(value)).join(" ");
  }

  function createCrossReferenceRelationshipSummaryCard(item = {}) {
    const card = document.createElement("article");
    card.className = "study-card semantic-card cross-reference-relationship-summary-card";
    const header = document.createElement("header");
    header.className = "semantic-card-header";
    const heading = document.createElement("h3");
    const range = document.createElement("div");
    const body = document.createElement("div");
    const counts = item.counts || {};
    const recordLines = asArray(item.records).slice(0, 12).map((record) => [
      `${record.relationshipDirection}: ${record.relationshipType}`,
      `${record.sourceEntityOrEventOrTheme} -> ${record.targetEntityOrEventOrTheme}`,
      record.targetScope ? `Target: ${record.targetScope}` : "",
      `Evidence: ${record.evidenceStrength}`,
      `Inference: ${record.inferenceLevel}`,
      `Provenance: ${record.provenance}`
    ].filter(Boolean).join(" | "));
    heading.textContent = "Cross-Reference Relationship Summary";
    range.className = "semantic-card-range";
    range.textContent = ["ICE_CROSS_REFERENCE_RELATIONSHIPS", item.activeScope, "foundation"].filter(Boolean).join(" | ");
    body.className = "semantic-card-body";
    header.append(heading, range);
    [
      createPassageFunctionSection("Prior", `${counts.prior || 0}`, { preserveExact: true }),
      createPassageFunctionSection("Current", `${counts.current || 0}`, { preserveExact: true }),
      createPassageFunctionSection("Future", `${counts.future || 0}`, { preserveExact: true }),
      createPassageFunctionSection("Related", `${counts.related || 0}`, { preserveExact: true }),
      createPassageFunctionSection("Relationship Record Structure", "", { list: item.relationshipRecordShape, plainList: true, preserveExact: true, collapsed: true, summaryLabel: "Show record shape" }),
      createPassageFunctionSection("Scoped Relationship Records", recordLines.length ? "" : "No scoped cross-reference relationship records are available yet.", { list: recordLines, plainList: true, preserveExact: true, collapsed: true, summaryLabel: "Show scoped relationship records" }),
      createPassageFunctionSection("Trust Rules", "", { list: item.trustRules, plainList: true, preserveExact: true, collapsed: true, summaryLabel: "Show trust rules" }),
      createWordingProvenanceSection({ source: "I.C.E. Cross-Reference Relationship Summary", label: "Cross-Reference Relationship Summary", layer: "Cross-Reference Relationship Summary / ICE_CROSS_REFERENCE_RELATIONSHIPS", storageKey: item.storageKey, scopePath: item.activeScope, rule: "Cross-reference relationship records are foundation records only. They summarize prior/current/future/related directions without crawling, automatic queue processing, automatic study progression, navigation, or scope mutation." })
    ].filter(Boolean).forEach((section) => body.appendChild(section));
    card.append(header, body);
    return card;
  }

  function renderCrossReferenceRelationshipSummary(term) {
    const container = document.getElementById("crossReferenceRelationshipSummaryCards");
    const count = document.getElementById("crossReferenceRelationshipSummaryCount");
    if (!container || !count) return;
    const record = crossReferenceRelationshipSummaryRecord();
    const records = [record];
    const filtered = records.filter((item) => matchesSearchQuery(crossReferenceRelationshipSummarySearchText(item), term));
    clearElement(container);
    count.textContent = `${filtered.length} summary item(s)`;
    if (!filtered.length) {
      appendEmpty(container, "No Cross-Reference Relationship Summary records match current filter.");
      return;
    }
    container.appendChild(createCard(
      "Cross-Reference Relationship Summary",
      [
        `Scoped relationship records: ${record.records.length}`,
        "Storage key: ICE_CROSS_REFERENCE_RELATIONSHIPS",
        "Directions: Prior, Current, Future, Related.",
        "Boundary: foundation summary only; no broad cross-reference generation, crawling, queue processing, navigation, or scope mutation."
      ].join("\n"),
      "cross-reference relationship foundation"
    ));
    filtered.forEach((item) => container.appendChild(createCrossReferenceRelationshipSummaryCard(item)));
  }

  function editorArchitectLayerCount(alias, label, options = {}) {
    const raw = asArray(studyData[alias]);
    const scoped = options.unscoped ? raw : scopedSemanticRecords(raw);
    return {
      alias,
      label,
      storageKey: STORAGE_KEYS[alias] || alias,
      rawCount: raw.length,
      scopedCount: scoped.length
    };
  }

  function editorArchitectPromotionCounts() {
    return [
      editorArchitectLayerCount("sourceDiscoveryIndex", "Discovery records"),
      editorArchitectLayerCount("mentionIndex", "Mention records"),
      editorArchitectLayerCount("referenceGraph", "Reference graph records"),
      editorArchitectLayerCount("semanticEvents", "Semantic events"),
      {
        alias: "scenePromotions",
        label: "Scenes",
        storageKey: "ICE_SCENE_MODELS / derived from ICE_CONTEXT_LOCK + ICE_TIMELINE_ITEMS",
        rawCount: promotedSceneRecords().length,
        scopedCount: promotedSceneRecords().length
      },
      editorArchitectLayerCount("timelineItems", "Timeline records"),
      editorArchitectLayerCount("orderedEvents", "Ordered events"),
      {
        alias: "timelinePromotions",
        label: "Accepted timeline promotions",
        storageKey: "ICE_TIMELINE_ITEMS / derived from ICE_ORDERED_EVENTS",
        rawCount: promotedTimelineRecords().length,
        scopedCount: promotedTimelineRecords().length
      },
      editorArchitectLayerCount("knowledgeGraph", "Knowledge graph records"),
      editorArchitectLayerCount("principleRelationships", "Principle relationships"),
      {
        alias: "relationshipPromotions",
        label: "Accepted relationship promotions",
        storageKey: "ICE_RELATIONSHIP_PROMOTIONS / derived from Context Lock, Entity Relation Roles, Timeline, Scene, Ordered Events, and Relationship Graph",
        rawCount: relationshipPromotionCandidates().length,
        scopedCount: promotedRelationshipRecords().length
      },
      {
        alias: "themePromotions",
        label: "Accepted theme promotions",
        storageKey: "ICE_STUDY_THEMES / derived from Context Lock, Timeline, Scene, Relationship, Teaching, and Principle records",
        rawCount: themePromotionCandidates().length,
        scopedCount: promotedThemeRecords().length
      },
      {
        alias: "literaryPromotions",
        label: "Accepted literary structure promotions",
        storageKey: "ICE_LITERARY_STRUCTURES / derived from source organization, Context, Timeline, Scene, Relationship, and Theme records",
        rawCount: literaryPromotionCandidates().length,
        scopedCount: promotedLiteraryRecords().length
      }
    ];
  }

  function editorArchitectPromotionLines() {
    const counts = editorArchitectPromotionCounts();
    return counts.map((item) => `${item.label}: ${item.scopedCount} scoped / ${item.rawCount} retained (${item.storageKey})`);
  }

  function promotionCoverageDisposition(record = {}) {
    const text = normalizeText([
      record.status,
      record.promotionStatus,
      record.validationStatus,
      record.resolutionStatus,
      record.appAccuracy,
      record.confidence,
      record.evidenceWeight,
      record.reason,
      record.rejectionReason,
      record.error,
      record.note
    ].join(" ")).toLowerCase();
    if (/reject|rejected|suppressed|excluded|out[-\s]?of[-\s]?scope|failed|failure|invalid|error/.test(text)) return "rejected";
    if (/unresolved|unknown|pending|ambiguous|needs review|not promoted|no promotion|missing/.test(text)) return "unresolved";
    return "promoted";
  }

  function promotionCoverageRows() {
    return scopedComputationCached("promotionCoverageRows", () => {
    const scopedRelationshipGraph = scopedSemanticRecords(studyData.relationshipGraph).filter((record) => relationshipGraphRecordAllowedInCurrentScope(record));
    const themeDiagnostics = themePromotionDiagnostics();
    const literaryDiagnostics = literaryPromotionDiagnostics();
    const fulfillmentRecords = [
      ...scopedSemanticRecords(studyData.passageFunctions).filter((item) => /fulfill|prophec|messianic/i.test(normalizeText([item.passageFunction, item.functionType, item.plainMeaning, item.fulfillmentMeaning, item.sourceGrounding].join(" ")))),
      ...scopedRelationshipGraph.filter((item) => /fulfill|prophec|messianic/i.test(normalizeText([item.relationshipType, item.semanticCategory, item.sourcePhrase, item.sourceGrounding].join(" ")))),
      ...timelineRelationshipRecords().filter((item) => /fulfill|prophec|messianic/i.test(normalizeText([item.relationshipType, item.whyConnected, item.sourcePhrase].join(" "))))
    ];

    const categories = [
      { label: "Source Discovery Records", records: scopedSemanticRecords(studyData.sourceDiscoveryIndex), discoveredFallback: scopedSemanticRecords(studyData.sourceDiscoveryIndex).length },
      { label: "Mention Records", records: scopedSemanticRecords(studyData.mentionIndex), discoveredFallback: scopedSemanticRecords(studyData.mentionIndex).length },
      { label: "Semantic Events", records: scopedSemanticRecords(studyData.semanticEvents), discoveredFallback: scopedSemanticRecords(studyData.semanticEvents).length },
      { label: "Scene Models", records: promotedSceneRecords(), discoveredFallback: Math.max(contextLockRecords().length, promotedTimelineRecords().length, scopedSemanticRecords(studyData.sceneModels).length) },
      { label: "Timeline Promotions", records: promotedTimelineRecords(), discoveredFallback: scopedSemanticRecords(studyData.orderedEvents).length },
      { label: "Knowledge Graph Promotions", records: knowledgeGraphRecords(), discoveredFallback: scopedSemanticRecords(studyData.knowledgeGraph).length },
      { label: "Relationship Promotions", records: promotedRelationshipRecords(), discoveredFallback: relationshipPromotionCandidates().length || scopedRelationshipGraph.length },
      { label: "Theme Promotions", records: themeDiagnostics.promoted, discoveredFallback: themeDiagnostics.groundedCandidates.length },
      { label: "Fulfillment Promotions", records: fulfillmentRecords, discoveredFallback: fulfillmentRecords.length },
      { label: "Literary Structure Promotions", records: literaryDiagnostics.promoted, discoveredFallback: literaryDiagnostics.groundedCandidates.length }
    ];
    return categories.map((category) => {
      const records = asArray(category.records);
      const discovered = Math.max(Number(category.discoveredFallback) || 0, records.length);
      const rejected = records.filter((record) => promotionCoverageDisposition(record) === "rejected").length;
      const unresolved = records.filter((record) => promotionCoverageDisposition(record) === "unresolved").length;
      const promoted = Math.max(0, records.length - rejected - unresolved);
      const coverage = metricPercent(promoted, discovered);
      return {
        label: category.label,
        discovered,
        promoted,
        rejected,
        unresolved,
        coverage,
        denominator: discovered,
        status: metricState({ denominator: discovered, numerator: promoted, unresolved }),
        scopeBasis: "selected scope / retained scoped records",
        denominatorRule: `${category.label} coverage = promoted records / grounded candidates; zero candidates are no candidates, not perfect health`
      };
    });
    });
  }

  function editorArchitectPromotionCoverageLines() {
    const rows = promotionCoverageRows();
    const lines = rows.map((item) => `${item.label}: discovered=${item.discovered}; promoted=${item.promoted}; rejected=${item.rejected}; unresolved=${item.unresolved}; coverage=${formatMetricPercent(item.coverage)}; status=${item.status}; denominator=${item.denominator}`);
    lines.push("Boundary: coverage metrics are visibility diagnostics, not quality scores. Higher coverage is not automatically better; false promotions are worse than missing promotions.");
    lines.push("Denominator rule: coverage uses grounded candidates for the current selected scope or retained scoped records, never the whole catalog unless explicitly labeled catalog coverage.");
    lines.push("Layer: ICE_PROMOTION_COVERAGE");
    return lines;
  }

  function timelinePromotionInspectorLines() {
    const ordered = scopedSemanticRecords(studyData.orderedEvents);
    const attempted = ordered.map(promotedTimelineRecordFromOrderedEvent);
    const accepted = attempted.filter((item) => item.promotionStatus === "promoted");
    const unresolved = attempted.filter((item) => item.promotionStatus !== "promoted");
    const rejected = [];
    const coverage = ordered.length ? Math.round((accepted.length / ordered.length) * 100) : 0;
    return [
      `Ordered Events: ${ordered.length}`,
      `Accepted Promotions: ${accepted.length}`,
      `Rejected Promotions: ${rejected.length}`,
      `Unresolved Promotions: ${unresolved.length}`,
      `Coverage: ${coverage}%`,
      accepted.length ? `Accepted examples: ${accepted.slice(0, 4).map((item) => `${item.sequenceNumber}. ${item.eventType} (${item.sourceReference || item.sourceScope})`).join(" | ")}` : "Accepted examples: none",
      unresolved.length ? `Unresolved examples: ${unresolved.slice(0, 4).map((item) => `${item.sequenceNumber || "?"}. ${item.eventType || "Unknown"} (${item.sourceScope || "no source scope"})`).join(" | ")}` : "Unresolved examples: none",
      "Boundary: Timeline promotions summarize accepted Ordered Events in source order only. They do not infer missing chronology, reorder events, create implied events, crawl, navigate, or process queues.",
      "Layer: ICE_TIMELINE_ITEMS promoted from ICE_ORDERED_EVENTS"
    ];
  }

  function scenePromotionInspectorLines() {
    const discovered = uniqueStudyList([
      ...contextLockRecords().map((item) => item.lockName || item.eventScope),
      ...promotedTimelineRecords().map((item) => item.timelineId || item.eventName),
      ...scopedSemanticRecords(studyData.sceneModels).map((item) => item.id || item.sceneId || item.sceneTitle)
    ].filter(Boolean));
    const promoted = promotedSceneRecords();
    const unresolved = promoted.filter((item) => item.promotionStatus !== "promoted");
    const rejected = [];
    const coverage = discovered.length ? Math.round(((promoted.length - unresolved.length) / discovered.length) * 100) : 0;
    return [
      `Discovered scenes: ${discovered.length}`,
      `Promoted scenes: ${Math.max(0, promoted.length - unresolved.length)}`,
      `Rejected scenes: ${rejected.length}`,
      `Unresolved scenes: ${unresolved.length}`,
      `Coverage: ${coverage}%`,
      promoted.length ? `Promoted examples: ${promoted.slice(0, 4).map((item) => `${item.sceneType}: ${item.sceneTitle || item.sceneId} (${item.sourceReference || item.sourceScope})`).join(" | ")}` : "Promoted examples: none",
      unresolved.length ? `Unresolved examples: ${unresolved.slice(0, 4).map((item) => `${item.sceneType || "Scene"}: ${item.sceneTitle || item.sceneId || "unresolved"} (${item.sourceScope || "no source scope"})`).join(" | ")}` : "Unresolved examples: none",
      "Boundary: Scene promotions summarize explicit Context Lock, Entity Registry, accepted Timeline, Ordered Event, and source-reference records only. They do not infer participants, authority, locations, movement, audience, or chronology.",
      "Layer: ICE_SCENE_MODELS promoted from ICE_CONTEXT_LOCK and ICE_TIMELINE_ITEMS"
    ];
  }

