  function integratedSemanticPipelineStages() {
    const resolutionCounts = (records = []) => qaDashboardResolutionCounts(records);
    const languageRecords = generatedLanguageRecords();
    const languageSupport = [
      ...languageRecords,
      ...morphologyPreviewRecords(),
      ...quotationBoundaryPreviewRecords(),
      ...pronounResolutionPreviewRecords()
    ];
    const contextRecords = [
      ...contextLockRecords(),
      ...sessionContinuityReviewRecords(),
      ...currentStudyScopePages()
    ];
    const semanticRecords = [
      ...Array.from(studyReferenceActors({ includeTechnical: true }).values()),
      ...scopedSemanticRecords(studyData.entityRegistry),
      ...promotedTimelineRecords(),
      ...promotedSceneRecords(),
      ...promotedRelationshipRecords(),
      ...promotedThemeRecords(),
      ...promotedLiteraryRecords()
    ];
    const reasoningRecords = [
      ...actionChainPreviewRecords(),
      ...causalityPreviewRecords(),
      ...consequenceChainPreviewRecords(),
      ...fulfillmentConfidencePreviewRecords()
    ];
    const languageExpansionRecords = [
      ...translationAlignmentPreviewRecords(),
      ...strongAlignmentPreviewRecords(),
      ...registeredLanguageAdapters()
    ];
    const registryRecords = [
      ...registeredOntologyClasses(),
      ...registeredCorpora(),
      ...registeredAuthorityClasses(),
      ...registeredPerspectiveModels(),
      ...registeredExpertModels(),
      ...registeredPresentationLenses()
    ];
    const presentationRecords = [
      ...qaArchitectureDashboardLines(),
      ...semanticHealthMetrics(),
      ...architectureGraphNodes()
    ];
    const stageDefs = [
      {
        pipelineStageId: "stage.0.primary_evidence",
        stageName: "Stage 0 - Primary Evidence",
        consumedRecords: activeSourcePageRecord() ? 1 : 0,
        producedRecords: scopedSemanticRecords(studyData.sourceDiscoveryIndex).length + scopedSemanticRecords(studyData.mentionIndex).length,
        unresolvedRecords: 0,
        authoritySource: "Primary Evidence Authority / Source Text Authority",
        evidenceDistance: 0,
        confidenceSummary: "source-grounded",
        provenanceSummary: activeSourcePageRecord() ? volumePageLabel(activeSourcePageRecord()) : currentStudyScopeLabel()
      },
      {
        pipelineStageId: "stage.1.language",
        stageName: "Stage 1 - Language Layer",
        consumedRecords: languageRecords.length,
        producedRecords: languageSupport.length,
        unresolvedRecords: resolutionCounts(languageSupport).unresolved,
        authoritySource: "Language Adapter Authority",
        evidenceDistance: 1,
        confidenceSummary: "preview-only language support",
        provenanceSummary: "english_surface_v1 plus registered original-language adapter contracts"
      },
      {
        pipelineStageId: "stage.2.context",
        stageName: "Stage 2 - Context Layer",
        consumedRecords: scopedSemanticRecords(studyData.sourceDiscoveryIndex).length + scopedSemanticRecords(studyData.mentionIndex).length,
        producedRecords: contextRecords.length,
        unresolvedRecords: resolutionCounts(contextRecords).unresolved,
        authoritySource: "Context Lock Authority",
        evidenceDistance: 2,
        confidenceSummary: "locked source context and scoped continuity",
        provenanceSummary: currentStudyScopeLabel()
      },
      {
        pipelineStageId: "stage.3.semantic",
        stageName: "Stage 3 - Semantic Layer",
        consumedRecords: contextRecords.length,
        producedRecords: semanticRecords.length,
        unresolvedRecords: resolutionCounts(semanticRecords).unresolved,
        authoritySource: "Context Lock Authority / Ontology Classification Authority",
        evidenceDistance: 3,
        confidenceSummary: "promoted scoped semantic records",
        provenanceSummary: "entity, timeline, scene, relationship, theme, and literary records"
      },
      {
        pipelineStageId: "stage.4.reasoning_support",
        stageName: "Stage 4 - Reasoning Support",
        consumedRecords: semanticRecords.length,
        producedRecords: reasoningRecords.length,
        unresolvedRecords: resolutionCounts(reasoningRecords).unresolved,
        authoritySource: "Perspective Authority / QA Diagnostic Authority",
        evidenceDistance: 6,
        confidenceSummary: "advisory reasoning support only",
        provenanceSummary: "action chains, causality, consequence chains, and fulfillment confidence"
      },
      {
        pipelineStageId: "stage.5.language_expansion",
        stageName: "Stage 5 - Language Expansion",
        consumedRecords: languageSupport.length,
        producedRecords: languageExpansionRecords.length,
        unresolvedRecords: resolutionCounts(languageExpansionRecords).unresolved,
        authoritySource: "Translation Authority / Strong's-Lexicon Authority",
        evidenceDistance: 7,
        confidenceSummary: "alignment support without equivalence enforcement",
        provenanceSummary: "translation, Strong alignment, and adapter registry contracts"
      },
      {
        pipelineStageId: "stage.6.registries",
        stageName: "Stage 6 - Registries",
        consumedRecords: 0,
        producedRecords: registryRecords.length,
        unresolvedRecords: 0,
        authoritySource: "Authority Registry / Corpus Registry / Ontology Registry",
        evidenceDistance: 7,
        confidenceSummary: "registry metadata only",
        provenanceSummary: "ontology, corpus, authority, perspective, expert, and lens registries"
      },
      {
        pipelineStageId: "stage.7.presentation",
        stageName: "Stage 7 - Presentation",
        consumedRecords: semanticRecords.length + registryRecords.length,
        producedRecords: presentationRecords.length,
        unresolvedRecords: resolutionCounts(presentationRecords).unresolved,
        authoritySource: "Presentation / Lens Authority",
        evidenceDistance: 8,
        confidenceSummary: "display-only summaries and diagnostics",
        provenanceSummary: "Editor / Architect View and QA Dashboard"
      }
    ];
    return stageDefs.map((stage) => ({
      ...stage,
      status: stage.producedRecords > 0 ? "active" : "inactive"
    }));
  }

  function integratedSemanticPipelineDiagnostics() {
    const stages = integratedSemanticPipelineStages();
    const activeStages = stages.filter((stage) => stage.status === "active");
    const inactiveStages = stages.filter((stage) => stage.status !== "active");
    const completeness = stages.length ? Math.round((activeStages.length / stages.length) * 100) : 0;
    const stageCoverage = stages.length ? Math.round((stages.reduce((sum, stage) => sum + (stage.producedRecords ? 1 : 0), 0) / stages.length) * 100) : 0;
    const warningStages = stages.filter((stage) => stage.unresolvedRecords > 0);
    return {
      stages,
      activeStages,
      inactiveStages,
      completeness,
      stageCoverage,
      warningStages
    };
  }

  function integratedSemanticPipelineLines() {
    const diagnostics = integratedSemanticPipelineDiagnostics();
    const lines = [
      `Pipeline stages: ${diagnostics.stages.length}`,
      `Active stages: ${diagnostics.activeStages.length}`,
      `Inactive stages: ${diagnostics.inactiveStages.length}`,
      `Pipeline completeness: ${diagnostics.completeness}%`,
      `Stage coverage: ${diagnostics.stageCoverage}%`,
      `Stages with unresolved counts: ${diagnostics.warningStages.length}`,
      "Record shape: pipelineStageId; stageName; consumedRecords; producedRecords; authoritySource; evidenceDistance; confidenceSummary; provenanceSummary; status",
      "Trust: pipeline visualizes existing records only. It does not create records, alter Context Lock, alter semantic authority, rewrite evidence, write storage, process queues, crawl, or change Study View output."
    ];
    diagnostics.stages.forEach((stage) => {
      lines.push([
        stage.stageName,
        `consumed=${stage.consumedRecords}`,
        `produced=${stage.producedRecords}`,
        `unresolved=${stage.unresolvedRecords}`,
        `authority=${stage.authoritySource}`,
        `evidenceDistance=${stage.evidenceDistance}`,
        `confidence=${stage.confidenceSummary}`,
        `provenance=${stage.provenanceSummary}`,
        `status=${stage.status}`
      ].join(" | "));
    });
    lines.push("Evidence distance progression: 0 Primary Evidence -> 1 Language -> 2 Context -> 3 Semantic -> 6 Reasoning Support -> 7 Expansion/Registries -> 8 Presentation.");
    lines.push("Authority progression: primary evidence and Context Lock constrain derived semantic, registry, reasoning, and presentation outputs.");
    lines.push("Boundary: integrated pipeline is observational and display-only, built from existing scoped runtime records and static registry metadata.");
    return lines;
  }

  function integratedSemanticPipelineDashboardLines() {
    const diagnostics = integratedSemanticPipelineDiagnostics();
    return [
      "Integrated Semantic Pipeline",
      `Pipeline completeness: ${diagnostics.completeness}%`,
      `Completed stages: ${diagnostics.activeStages.length}`,
      `Inactive stages: ${diagnostics.inactiveStages.length}`,
      `Stage coverage: ${diagnostics.stageCoverage}%`,
      `Stage health: ${diagnostics.warningStages.length ? `${diagnostics.warningStages.length} stage(s) contain unresolved diagnostics` : "all active stages clean"}`,
      "Boundary: pipeline is display-only and does not influence semantic output."
    ];
  }

  function semanticExplainabilitySourceGroups() {
    return [
      { recordType: "Context Lock", records: contextLockRecords(), producedByStage: "Stage 2 - Context Layer", authoritySource: "Context Lock Authority", evidenceDistance: 2, supportingRules: ["Context precedes meaning", "Context Lock remains authoritative"], consumedRegistries: ["Authority Registry"] },
      { recordType: "Entity Records", records: [...Array.from(studyReferenceActors({ includeTechnical: true }).values()), ...scopedSemanticRecords(studyData.entityRegistry)], producedByStage: "Stage 3 - Semantic Layer", authoritySource: "Ontology Classification Authority", evidenceDistance: 3, supportingRules: ["Entities may not rewrite Context Lock", "Locations remain locations; actors remain actors"], consumedRegistries: ["Ontology Registry", "Authority Registry"] },
      { recordType: "Timeline Records", records: promotedTimelineRecords(), producedByStage: "Stage 3 - Semantic Layer", authoritySource: "Context Lock Authority / Timeline Promotion Rules", evidenceDistance: 4, supportingRules: ["Timeline summarizes source order", "Timeline may not infer missing chronology"], consumedRegistries: ["Authority Registry"] },
      { recordType: "Scene Records", records: promotedSceneRecords(), producedByStage: "Stage 3 - Semantic Layer", authoritySource: "Context Lock Authority / Scene Promotion Rules", evidenceDistance: 4, supportingRules: ["Scenes summarize context", "Scenes may not create participants"], consumedRegistries: ["Authority Registry", "Ontology Registry"] },
      { recordType: "Relationship Records", records: promotedRelationshipRecords(), producedByStage: "Stage 3 - Semantic Layer", authoritySource: "Relationship Promotion Rules", evidenceDistance: 5, supportingRules: ["Relationships may not rewrite context", "Relationships may not create actors or locations"], consumedRegistries: ["Authority Registry", "Ontology Registry"] },
      { recordType: "Theme Records", records: promotedThemeRecords(), producedByStage: "Stage 3 - Semantic Layer", authoritySource: "Theme Promotion Rules", evidenceDistance: 6, supportingRules: ["Themes summarize semantic records", "Themes may not create doctrine"], consumedRegistries: ["Authority Registry", "Lens Registry"] },
      { recordType: "Literary Structure Records", records: promotedLiteraryRecords(), producedByStage: "Stage 3 - Semantic Layer", authoritySource: "Literary Promotion Rules", evidenceDistance: 6, supportingRules: ["Literary structures summarize source organization", "Possible structures remain possible"], consumedRegistries: ["Authority Registry", "Lens Registry"] },
      { recordType: "Language Records", records: generatedLanguageRecords(), producedByStage: "Stage 1 - Language Layer", authoritySource: "Language Adapter Authority", evidenceDistance: 1, supportingRules: ["Language records are advisory", "Language may not rewrite source text"], consumedRegistries: ["Language Adapter Registry", "Authority Registry"] },
      { recordType: "Action Chains", records: actionChainPreviewRecords(), producedByStage: "Stage 4 - Reasoning Support", authoritySource: "QA / Diagnostic Authority", evidenceDistance: 6, supportingRules: ["Action chains are preview-only", "No doctrine or motive inference"], consumedRegistries: ["Authority Registry", "Lens Registry"] },
      { recordType: "Causality", records: causalityPreviewRecords(), producedByStage: "Stage 4 - Reasoning Support", authoritySource: "QA / Diagnostic Authority", evidenceDistance: 6, supportingRules: ["Causality requires explicit source wording", "No motive or fulfillment inference"], consumedRegistries: ["Authority Registry"] },
      { recordType: "Consequence Chains", records: consequenceChainPreviewRecords(), producedByStage: "Stage 4 - Reasoning Support", authoritySource: "QA / Diagnostic Authority", evidenceDistance: 7, supportingRules: ["Only explicit causal links may be chained", "Unresolved is better than wrong"], consumedRegistries: ["Authority Registry"] },
      { recordType: "Fulfillment Confidence", records: fulfillmentConfidencePreviewRecords(), producedByStage: "Stage 4 - Reasoning Support", authoritySource: "Fulfillment Confidence Framework", evidenceDistance: 7, supportingRules: ["Explicit fulfillment is only explicit when source says so", "Typology must remain typology unless source marks fulfillment"], consumedRegistries: ["Authority Registry", "Perspective Registry"] },
      { recordType: "Translation Alignment", records: translationAlignmentPreviewRecords(), producedByStage: "Stage 5 - Language Expansion", authoritySource: "Translation Authority", evidenceDistance: 7, supportingRules: ["Alignment does not imply equivalence", "Translation models may not override source wording"], consumedRegistries: ["Language Adapter Registry", "Perspective Registry", "Authority Registry"] },
      { recordType: "Strong Alignment", records: strongAlignmentPreviewRecords(), producedByStage: "Stage 5 - Language Expansion", authoritySource: "Strong's / Lexicon Authority", evidenceDistance: 7, supportingRules: ["Strong alignment is attributable support", "Strong alignment does not imply meaning authority"], consumedRegistries: ["Language Adapter Registry", "Expert Registry", "Authority Registry"] }
    ];
  }

  function semanticExplainabilityRecord(group, record = {}, index = 0) {
    const textRecord = normalizeText(record);
    const recordId = record.explainabilityId
      || record.id
      || record.recordId
      || record.entityId
      || record.timelineId
      || record.sceneId
      || record.relationshipId
      || record.themeId
      || record.literaryId
      || record.tokenId
      || record.actionId
      || record.causalityId
      || record.consequenceId
      || record.fulfillmentId
      || record.alignmentId
      || record.strongAlignmentId
      || record.canonicalKey
      || `${normalizeText(group.recordType).toLowerCase().replace(/[^a-z0-9]+/g, ".")}.${index + 1}`;
    const sourceEvidence = record.sourceEvidence
      || record.evidence
      || record.evidenceChain
      || record.sourceText
      || record.sourcePhrase
      || record.sourceReference
      || record.verseRange
      || record.sourceScope
      || "source evidence not recorded on source record";
    const confidence = record.confidence || record.evidenceWeight || record.appAccuracy || record.status || record.promotionStatus || "confidence not recorded on source record";
    const explicitProvenance = Boolean(record.provenance || record.sourceProvenance || record.createdFrom);
    const explicitAuthority = Boolean(record.authoritySource || record.authority || record.sourceAuthority || record.authorityPath);
    const explicitConfidence = Boolean(record.confidence || record.evidenceWeight || record.appAccuracy || record.status || record.promotionStatus);
    const explicitEvidence = Boolean(record.sourceEvidence || record.evidence || record.evidenceChain || record.sourceText || record.sourcePhrase || record.sourceReference || record.verseRange || record.sourceScope);
    const authorityStatus = explicitAuthority ? "explicit authority" : (group.authoritySource ? "inherited authority" : "missing authority");
    return {
      explainabilityId: `explain.${normalizeText(group.recordType).toLowerCase().replace(/[^a-z0-9]+/g, ".")}.${index + 1}`,
      recordType: group.recordType,
      recordId,
      createdFrom: record.createdFrom || record.parentRecord || record.parentId || group.producedByStage,
      sourceEvidence,
      consumedRecords: asArray(record.consumedRecords || record.supportingRecords || record.supportingEvents || record.supportingScenes || record.supportingRelationships || record.evidenceLinks || record.timelineReferences).slice(0, 8),
      producedByStage: group.producedByStage,
      authoritySource: record.authoritySource || record.authority || record.sourceAuthority || group.authoritySource,
      authorityStatus,
      authorityPath: asArray(record.authorityPath || [group.authoritySource]).join(" -> "),
      evidenceDistance: record.evidenceDistance ?? group.evidenceDistance,
      confidence,
      provenance: record.provenance || record.sourceProvenance || `I.C.E. Explainability derived from existing scoped ${group.recordType} display/runtime records only`,
      supportingRules: group.supportingRules,
      consumedRegistries: group.consumedRegistries,
      activePerspectiveModels: registeredPerspectiveModels().filter((model) => model.status !== "inactive").map((model) => model.perspectiveId).slice(0, 8),
      activeExpertModels: registeredExpertModels().filter((model) => model.status !== "inactive").map((model) => model.expertId).slice(0, 8),
      activeLenses: registeredPresentationLenses().filter((lens) => lens.status !== "inactive").map((lens) => lens.lensId).slice(0, 10),
      missingProvenance: !explicitProvenance,
      missingAuthority: !explicitAuthority,
      missingConfidence: !explicitConfidence,
      missingEvidenceChain: !explicitEvidence,
      status: /unresolved|ambiguous|pending|unknown/i.test(`${confidence} ${textRecord}`) ? "review" : "explainable"
    };
  }

  function semanticExplainabilityRecords() {
    return scopedComputationCached("semanticExplainabilityRecords", () => semanticExplainabilitySourceGroups()
      .flatMap((group) => asArray(group.records).slice(0, 180).map((record, index) => semanticExplainabilityRecord(group, record, index))));
  }

  function semanticExplainabilityDiagnostics() {
    const records = semanticExplainabilityRecords();
    const missingProvenance = records.filter((record) => record.missingProvenance);
    const missingAuthority = records.filter((record) => record.missingAuthority);
    const missingConfidence = records.filter((record) => record.missingConfidence);
    const missingEvidenceChain = records.filter((record) => record.missingEvidenceChain);
    const explainable = records.filter((record) => record.status === "explainable");
    const coverage = records.length ? Math.round((explainable.length / records.length) * 100) : 100;
    const byType = records.reduce((counts, record) => {
      counts[record.recordType] = (counts[record.recordType] || 0) + 1;
      return counts;
    }, {});
    return {
      records,
      explainable,
      missingProvenance,
      missingAuthority,
      missingConfidence,
      missingEvidenceChain,
      coverage,
      byType
    };
  }

  function semanticExplainabilityInspectorLines() {
    const diagnostics = semanticExplainabilityDiagnostics();
    const sample = diagnostics.records.slice(0, 12).map((record) => [
      record.recordType,
      `id=${record.recordId}`,
      `stage=${record.producedByStage}`,
      `authority=${record.authoritySource}`,
      `authorityStatus=${record.authorityStatus}`,
      `distance=${record.evidenceDistance}`,
      `confidence=${normalizeText(record.confidence)}`,
      `provenance=${trimText(record.provenance, 80)}`,
      `status=${record.status}`
    ].join(" | "));
    return [
      `Explainability records: ${diagnostics.records.length}`,
      `Explainability coverage: ${diagnostics.coverage}%`,
      `Records missing provenance: ${diagnostics.missingProvenance.length}`,
      `Records missing authority: ${diagnostics.missingAuthority.length}`,
      "Authority labels: explicit authority means present on the source/runtime record; inherited authority means supplied by the explainability group/registry; missing authority means neither source nor group supplied authority.",
      `Records missing confidence: ${diagnostics.missingConfidence.length}`,
      `Records missing evidence chain: ${diagnostics.missingEvidenceChain.length}`,
      `Categories: ${languageCountLine(diagnostics.byType)}`,
      "Record shape: explainabilityId; recordType; recordId; createdFrom; sourceEvidence; consumedRecords; producedByStage; authoritySource; authorityPath; evidenceDistance; confidence; provenance; supportingRules; consumedRegistries; activePerspectiveModels; activeExpertModels; activeLenses; status",
      "Selected record: first available explainability sample from the current scoped runtime records.",
      "Sample records:",
      ...(sample.length ? sample : ["No explainability records generated from current scoped records."]),
      "Dependency chain: source evidence -> produced stage -> authority path -> consumed registries -> active perspectives/experts/lenses.",
      "Trust: explainability describes records only. It does not alter records, create semantic records, rewrite evidence, mutate Context Lock, write storage, process queues, crawl, or change Study View output."
    ];
  }

  function semanticExplainabilityDashboardLines() {
    const diagnostics = semanticExplainabilityDiagnostics();
    return [
      "Explainability Summary",
      `Explainable records: ${diagnostics.explainable.length}`,
      `Records missing provenance: ${diagnostics.missingProvenance.length}`,
      `Records missing authority: ${diagnostics.missingAuthority.length}`,
      "Authority basis: explicit authority gaps remain visible even when provenance graph nodes inherit registry/governed authority for display.",
      `Records missing confidence: ${diagnostics.missingConfidence.length}`,
      `Records missing evidence chain: ${diagnostics.missingEvidenceChain.length}`,
      `Explainability coverage: ${diagnostics.coverage}%`,
      "Boundary: explainability is generated from existing scoped/runtime records and registry metadata only."
    ];
  }

  function provenanceGraphRecordTypes() {
    return [
      "Primary Evidence",
      "Context Lock",
      "Language Records",
      "Entity Records",
      "Timeline Records",
      "Scene Records",
      "Relationship Records",
      "Theme Records",
      "Literary Structure Records",
      "Action Chains",
      "Causality",
      "Consequence Chains",
      "Fulfillment Confidence",
      "Translation Alignment",
      "Strong Alignment",
      "Perspective Models",
      "Expert Models",
      "Lenses"
    ];
  }

  function provenanceGraphNodeFromExplainability(record = {}, index = 0) {
    const recordType = normalizeText(record.recordType || "Derived Record") || "Derived Record";
    const recordId = normalizeText(record.recordId || record.explainabilityId || `record.${index + 1}`) || `record.${index + 1}`;
    return {
      provenanceNodeId: `prov.node.${normalizeText(recordType).toLowerCase().replace(/[^a-z0-9]+/g, ".")}.${index + 1}`,
      recordType,
      recordId,
      label: `${recordType}: ${trimText(recordId, 80)}`,
      evidenceDistance: record.evidenceDistance ?? 8,
      authoritySource: record.authoritySource || "authority not recorded",
      authorityStatus: record.authorityStatus || (/not recorded/i.test(normalizeText(record.authoritySource)) ? "missing authority" : "explicit authority"),
      confidence: record.confidence || "confidence not recorded",
      provenance: record.provenance || "provenance not recorded",
      status: record.missingProvenance || record.missingAuthority || record.missingConfidence ? "review" : "connected"
    };
  }

  function provenanceGraphDiagnostics() {
    return scopedComputationCached("provenanceGraphDiagnostics", () => {
    const explainability = semanticExplainabilityDiagnostics();
    const derivedNodes = explainability.records.map((record, index) => provenanceGraphNodeFromExplainability(record, index));
    const sourceNode = {
      provenanceNodeId: "prov.node.primary.evidence.current.scope",
      recordType: "Primary Evidence",
      recordId: currentStudyScopeLabel(),
      label: `Primary Evidence: ${currentStudyScopeLabel()}`,
      evidenceDistance: 0,
      authoritySource: "Primary Evidence Authority / Source Text Authority",
      confidence: "source-grounded",
      provenance: activeSourcePageRecord() ? volumePageLabel(activeSourcePageRecord()) : currentStudyScopeLabel(),
      status: "connected"
    };
    const perspectiveNodes = registeredPerspectiveModels().map((model, index) => ({
      provenanceNodeId: `prov.node.perspective.${index + 1}`,
      recordType: "Perspective Models",
      recordId: model.perspectiveId,
      label: `Perspective Model: ${model.perspectiveType}`,
      evidenceDistance: model.evidenceDistance ?? 7,
      authoritySource: "Perspective Authority",
      confidence: model.confidence || "registry metadata",
      provenance: model.provenance || "Perspective registry",
      status: "registry"
    }));
    const expertNodes = registeredExpertModels().map((model, index) => ({
      provenanceNodeId: `prov.node.expert.${index + 1}`,
      recordType: "Expert Models",
      recordId: model.expertId,
      label: `Expert Model: ${model.expertType}`,
      evidenceDistance: model.evidenceDistance ?? 7,
      authoritySource: "Expert Authority",
      confidence: model.confidencePolicy || "registry metadata",
      provenance: model.provenance || "Expert registry",
      status: "registry"
    }));
    const lensNodes = registeredPresentationLenses().map((lens, index) => ({
      provenanceNodeId: `prov.node.lens.${index + 1}`,
      recordType: "Lenses",
      recordId: lens.lensId,
      label: `Lens: ${lens.lensName}`,
      evidenceDistance: 8,
      authoritySource: "Presentation / Lens Authority",
      confidence: lens.status || "registry metadata",
      provenance: "Lens registry",
      status: "registry"
    }));
    const nodes = [sourceNode, ...derivedNodes, ...perspectiveNodes, ...expertNodes, ...lensNodes];
    const sourceEdges = derivedNodes.map((node, index) => ({
      provenanceEdgeId: `prov.edge.source.${index + 1}`,
      sourceNode: sourceNode.provenanceNodeId,
      targetNode: node.provenanceNodeId,
      edgeType: node.evidenceDistance <= 2 ? "derived_from" : "informed_by",
      evidenceFlow: `Distance 0 -> ${node.evidenceDistance}`,
      authorityFlow: `${sourceNode.authoritySource} constrains ${node.authoritySource}`,
      confidenceFlow: `${sourceNode.confidence} -> ${node.confidence}`,
      status: "connected"
    }));
    const registryEdges = [
      ...perspectiveNodes.flatMap((node, index) => derivedNodes.filter((item) => /Translation Alignment|Strong Alignment|Fulfillment Confidence/i.test(item.recordType)).slice(0, 12).map((target, targetIndex) => ({
        provenanceEdgeId: `prov.edge.perspective.${index + 1}.${targetIndex + 1}`,
        sourceNode: node.provenanceNodeId,
        targetNode: target.provenanceNodeId,
        edgeType: "attributed_to",
        evidenceFlow: `Distance ${node.evidenceDistance} attribution -> ${target.evidenceDistance}`,
        authorityFlow: `${node.authoritySource} may inform but not override ${target.authoritySource}`,
        confidenceFlow: "attributed perspective influence remains separate",
        status: "registry"
      }))),
      ...expertNodes.flatMap((node, index) => derivedNodes.filter((item) => /Strong Alignment|Translation Alignment/i.test(item.recordType)).slice(0, 8).map((target, targetIndex) => ({
        provenanceEdgeId: `prov.edge.expert.${index + 1}.${targetIndex + 1}`,
        sourceNode: node.provenanceNodeId,
        targetNode: target.provenanceNodeId,
        edgeType: "attributed_to",
        evidenceFlow: `Distance ${node.evidenceDistance} attribution -> ${target.evidenceDistance}`,
        authorityFlow: `${node.authoritySource} illuminates but does not replace evidence`,
        confidenceFlow: "expert confidence remains attributable",
        status: "registry"
      }))),
      ...lensNodes.slice(0, 12).map((node, index) => ({
        provenanceEdgeId: `prov.edge.lens.${index + 1}`,
        sourceNode: derivedNodes[0]?.provenanceNodeId || sourceNode.provenanceNodeId,
        targetNode: node.provenanceNodeId,
        edgeType: "presented_by",
        evidenceFlow: `Derived records -> Distance ${node.evidenceDistance} presentation`,
        authorityFlow: "Presentation consumes records but may not rewrite evidence",
        confidenceFlow: "presentation preserves confidence labels",
        status: "registry"
      }))
    ];
    const edges = [...sourceEdges, ...registryEdges];
    const connectedNodeIds = new Set(edges.flatMap((edge) => [edge.sourceNode, edge.targetNode]));
    const missingProvenance = nodes.filter((node) => /not recorded/i.test(normalizeText(node.provenance)));
    const missingAuthority = nodes.filter((node) => /missing authority|authority not recorded/i.test(normalizeText([node.authorityStatus, node.authoritySource].join(" "))));
    const missingConfidence = nodes.filter((node) => /not recorded/i.test(normalizeText(node.confidence)));
    const disconnected = nodes.filter((node) => !connectedNodeIds.has(node.provenanceNodeId));
    return {
      nodes,
      edges,
      sourceEvidenceNodes: nodes.filter((node) => node.recordType === "Primary Evidence"),
      derivedRecordNodes: nodes.filter((node) => node.evidenceDistance > 0),
      missingProvenance,
      missingAuthority,
      missingConfidence,
      disconnected
    };
    });
  }

  function provenanceGraphInspectorLines() {
    const graph = provenanceGraphDiagnostics();
    const typeCounts = graph.nodes.reduce((counts, node) => {
      const type = normalizeText(node.recordType || "Unknown") || "Unknown";
      counts[type] = (counts[type] || 0) + 1;
      return counts;
    }, {});
    const samplePaths = graph.edges.slice(0, 14).map((edge) => `${edge.sourceNode} -> ${edge.targetNode} | ${edge.edgeType} | evidence=${edge.evidenceFlow} | authority=${edge.authorityFlow}`);
    return [
      `Provenance nodes: ${graph.nodes.length}`,
      `Provenance edges: ${graph.edges.length}`,
      `Supported node types: ${provenanceGraphRecordTypes().join("; ")}`,
      `Node type counts: ${languageCountLine(typeCounts)}`,
      `Source evidence nodes: ${graph.sourceEvidenceNodes.length}`,
      `Derived record nodes: ${graph.derivedRecordNodes.length}`,
      `Missing provenance nodes: ${graph.missingProvenance.length}`,
      `Missing authority nodes: ${graph.missingAuthority.length}`,
      `Missing confidence nodes: ${graph.missingConfidence.length}`,
      `Disconnected provenance nodes: ${graph.disconnected.length}`,
      "Authority basis: provenance nodes use authorityStatus from explainability; inherited authority remains labeled and no longer hides raw source-record authority gaps.",
      "Node shape: provenanceNodeId; recordType; recordId; label; evidenceDistance; authoritySource; authorityStatus; confidence; provenance; status",
      "Edge shape: provenanceEdgeId; sourceNode; targetNode; edgeType; evidenceFlow; authorityFlow; confidenceFlow; status",
      "Supported edge types: derived_from; informed_by; consumed_by; presented_by; constrained_by; attributed_to",
      "Sample provenance paths:",
      ...(samplePaths.length ? samplePaths : ["No provenance paths available for the current scoped records."]),
      "Trust: provenance graph describes record lineage only. It does not alter records, create semantic authority, rewrite evidence, mutate Context Lock, write storage, crawl, process queues, or change Study View output."
    ];
  }

  function provenanceGraphDashboardLines() {
    const graph = provenanceGraphDiagnostics();
    return [
      "Provenance Graph Summary",
      `Provenance graph node count: ${graph.nodes.length}`,
      `Provenance graph edge count: ${graph.edges.length}`,
      `Missing provenance count: ${graph.missingProvenance.length}`,
      `Missing authority count: ${graph.missingAuthority.length}`,
      `Missing confidence count: ${graph.missingConfidence.length}`,
      `Disconnected provenance nodes: ${graph.disconnected.length}`,
      "Boundary: provenance graph is runtime/display-only and does not persist graph storage or influence semantic output."
    ];
  }

  function semanticVerificationRecord(category, rule, result, severity, evidence, authority, provenance, evidenceDistance = 8, confidence = "observational") {
    return {
      verificationId: `verify.${normalizeText(category).toLowerCase().replace(/[^a-z0-9]+/g, ".")}.${normalizeText(rule).toLowerCase().replace(/[^a-z0-9]+/g, ".")}`,
      verificationCategory: category,
      verificationRule: rule,
      evaluatedRecord: currentStudyScopeLabel(),
      result,
      severity,
      evidence,
      authority,
      provenance,
      evidenceDistance,
      confidence,
      status: result
    };
  }

